package bind

import (
	"crypto/rand"
	"errors"
	"fmt"
	"net"
	"net/netip"
	"sync"
	"sync/atomic"
	"syscall"
	"time"

	"github.com/amnezia-vpn/amneziawg-go/conn"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/frame"
	"github.com/7mind/wanbond/internal/reseq"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// socketRecvBuffer is the SO_RCVBUF requested on every per-path socket, matching
// wireguard-go's StdNetBind (~7 MiB). A large receive buffer absorbs the bursts a
// bonded, reordered flow delivers while the userspace engine catches up; the
// pass-through P0 Bind used the OS default and lost datagrams under load (P0
// findings §1/§2). The kernel silently caps the request at net.core.rmem_max, so
// the effective size may be smaller on an untuned host — best-effort by design.
const socketRecvBuffer = 7 << 20

// multipathBatchSize is the number of datagrams a ReceiveFunc / Send handles per
// call. T12 keeps it at 1 (one syscall per datagram, per path); GSO/GRO batching
// is best-effort future work (P0 findings §2) tracked separately and does not
// change the wire format.
const multipathBatchSize = 1

// maxDatagram bounds a single received outer datagram. It comfortably exceeds a
// full-MTU inner packet plus every outer/WG/amnezia-junk overhead.
const maxDatagram = 65535

// Receive-resequencer tuning (T18), sized against P0 findings §6.
//
// resequencerWindow is the maximum span of outer-seq positions the receive
// resequencer buffers while it waits for an out-of-order frame. WG's inner RFC
// 6479 anti-replay window is 8128 messages (docs/p0-findings.md §6); the window
// here sits ~4x below that, so even a worst-case burst of reordered/held frames
// stays comfortably inside the inner filter's tolerance while spanning far more
// packets than the measured ~19 ms emulated cross-path skew (and the larger,
// more variable real Starlink/5G skew) needs at realistic per-path rates.
//
// resequencerTimeout bounds how long a head-of-line-blocked run is held for a
// missing (presumed-lost) lower frame before that gap is skipped and the run
// released. It caps the added latency — and the stall a slow/lossy path can
// impose on the whole bond (P0 §7 head-of-line concern) — to a few multiples of
// a Starlink RTT (~45 ms) rather than holding a gap forever.
const (
	resequencerWindow  = 2048
	resequencerTimeout = 250 * time.Millisecond
)

var (
	errNoHealthyPath = errors.New("bind: no healthy path with a known remote endpoint")
	// errPacerShedding is returned by Send when the scheduler shed the datagram for
	// pacing (PickPaced) while paths are healthy — deliberate rate limiting, NOT an
	// outage. It is DISTINCT from errNoHealthyPath so operator logs and the e2e
	// log-grep harness can tell shedding from total path failure (the drop behavior is
	// identical to the pre-existing no-path case; only the diagnostic differs). The
	// coalesced, rate-limited "pacer shedding" record is emitted by the scheduler.
	errPacerShedding = errors.New("bind: datagram shed by send pacer (paths healthy, rate limited)")
	errClosed        = net.ErrClosed
)

// pathState is one configured uplink: its source-bound UDP socket, stable
// path-id, its own decode Codec (each path receives on its own goroutine, so the
// Codec's scratch is never shared), and the per-path remote endpoint. The remote
// is either configured (edge dest_addr / peer endpoint) or LEARNED from inbound
// traffic (concentrator) — but it lives strictly BELOW the engine's single
// virtual endpoint, so the engine never sees this per-path bookkeeping churn.
type pathState struct {
	name  string
	id    uint8
	src   netip.Addr
	conn  *net.UDPConn
	codec *frame.Codec
	// prober is this path's own probe initiator (nil when the bind runs without the
	// probe transport). It is set at path creation and immutable for the path's life,
	// so the Bind-owned receive goroutine reaches it via the pathState it already
	// holds — NOT through a shared, dynamically-mutated m.probers slice — which is
	// what keeps echo handling race-free while paths are added/removed at runtime (T30).
	prober *telemetry.Prober

	// txBytes/rxBytes are cumulative OUTER-wire byte counters for this path, the
	// per-path traffic accounting the /metrics exposition reports (T23). txBytes counts
	// the DATA-frame wire bytes this path egresses on the Send hot path; rxBytes counts
	// every outer datagram this path's readLoop receives (DATA, PROBE, and echo alike —
	// the true received wire volume). They are atomics so the send/receive hot paths
	// increment them WITHOUT taking m.mu (lock-free), and the scrape/snapshot path reads
	// them with a plain atomic Load; a single writer per counter (Send holds m.mu while
	// choosing the path, and each path has exactly one readLoop) means the Add is
	// uncontended in the common case. "Bytes on Starlink vs 5G" — the data-thrift signal
	// (requirement 2) — is exactly txBytes: when the weighted scheduler collapses to the
	// primary under sub-capacity load, the backup path's Send count stays ~flat.
	txBytes atomic.Uint64
	rxBytes atomic.Uint64

	mu        sync.Mutex
	remote    netip.AddrPort
	hasRemote bool
}

// deferredPath is a configured path whose WELL-FORMED source_addr was not yet
// assignable at Open (net.ListenUDP -> EADDRNOTAVAIL: no interface holds the
// address, e.g. a 5G modem with no DHCP lease at boot). Rather than tear the whole
// bond down, Open records the path here instead of binding it: the tunnel comes up
// on the paths that DID bind, and this path stays DOWN — its prober, never fed an
// echo, reports StateDown, which the scheduler excludes from Pick, exactly as the
// runtime path-down model treats a live-but-silent path. It carries the boot-time
// prober so the T55 background reconcile that retries the bind reuses the SAME
// path-id stamp instead of minting a new one. prober is nil only on a bind without
// the probe transport, which never defers (see Open).
type deferredPath struct {
	def    config.Path
	prober *telemetry.Prober
}

func (ps *pathState) setRemote(ap netip.AddrPort) {
	ps.mu.Lock()
	ps.remote, ps.hasRemote = ap, true
	ps.mu.Unlock()
}

func (ps *pathState) getRemote() (netip.AddrPort, bool) {
	ps.mu.Lock()
	defer ps.mu.Unlock()
	return ps.remote, ps.hasRemote
}

// Multipath is the P1 bonding conn.Bind: one UDP socket per configured path
// (bound to the path's source address), all fronted by a SINGLE stable virtual
// endpoint the engine holds per peer. Send wraps each opaque WireGuard datagram
// in an outer DATA frame (own outer-seq + path-id) and picks a path; one
// Bind-owned reader per path unwraps DATA frames into the shared resequencer, and
// a SINGLE engine-facing ReceiveFunc drains it and hands the inner WG datagram up
// under the shared virtual endpoint (the fan-in that lets paths be added/removed at
// runtime without the engine spawning receive goroutines — T30). It replaces
// bind.Passthrough behind the same conn.Bind seam (device wiring is unchanged).
//
// Lifecycle: the sockets live for the duration of an Open→Close span, NOT the
// Multipath's whole life. The amneziawg engine calls Close() before every Open()
// (device.upLocked → BindUpdate → closeBindLocked, and on IpcSet listen_port /
// route-change events) and cycles Close↔Open on Down/Up, so — exactly like
// conn.StdNetBind — Open creates the per-path sockets and Close tears them down
// AND clears the path state so the next Open rebuilds from scratch. The "closed"
// state is simply "no bound sockets" (len(paths)==0); there is no separate sticky
// flag that a later Open would have to reset.
//
// Path policy: an injected sched.Scheduler (T15) chooses the egress path per
// datagram. The P1 MVP wires an active-backup scheduler (all traffic on the
// preferred primary, transparent failover to a backup on a T13 path-DOWN signal
// with failback hysteresis); the weighted/FEC-aware policy (T21) is a different
// Scheduler swapped in here with no Bind change. No FEC/resequencing yet
// (P2/P3), but every DATA frame carries its outer-seq and path-id so T18/T24 can
// consume them.
// ProberFactory mints a *telemetry.Prober for a path admitted at runtime (T30),
// stamped with the given stable path-id. The device wires it capturing the SAME
// per-boot session id, prober config, clock, PSK, and logger the boot-time probers
// were built with, so a runtime path's liveness is measured identically to a
// boot-time path (its probes join the same session so the peer's reflector adopts
// them without a challenge reset). It is nil on a bind built without the probe
// transport (the T12 unit tests), which therefore cannot add paths at runtime.
type ProberFactory func(name string, id uint8) *telemetry.Prober

type Multipath struct {
	psk       config.Key
	defs      []config.Path
	scheduler sched.Scheduler

	// classify maps each outbound datagram to its pacer traffic class from the inner
	// WireGuard message type, parameterized by the tunnel's Amnezia obfuscation profile
	// so a WireGuard control frame (handshake/keepalive) is recognised — and pacing-
	// exempted — under advanced security too, not only in vanilla mode (defect D22). It
	// is immutable after construction and holds no lock, so Send reads it off m.mu.
	classify wgClassifier

	// probers is the BOOT-TIME per-path probe initiator set, in path order, shared
	// with the scheduler (the SAME *telemetry.Prober values back its PathHealth). At
	// Open each is bound onto its pathState (ps.prober), and thereafter the hot paths
	// reach a path's prober through the pathState — never by indexing this slice — so
	// a runtime path add/remove cannot race echo handling. It is nil when the bind
	// runs without the probe transport (the T12 unit tests, which drive selection via
	// AlwaysUp); a nil here also gates the whole probe loop off.
	probers []*telemetry.Prober
	// newProber mints a prober for a path admitted at runtime (T30); nil disables
	// runtime path addition (a bind without the probe transport).
	newProber ProberFactory
	// deferredListen binds a reconciled deferred path's socket (T55 background
	// reconcile). It is an injection seam: the default pins the source IP (net.ListenUDP,
	// matching AddPath's runtime bind), and a test overrides it to drive the
	// deferred→bound transition deterministically — a source_addr "becoming assignable"
	// — without a real interface address having to appear on the host. Immutable after
	// construction, never nil.
	deferredListen func(src netip.Addr, port uint16) (*net.UDPConn, error)
	// reflector answers inbound peer probes (IsEcho=false) with an authenticated
	// echo. A single Reflector serves every path (its anti-replay is PathID-keyed)
	// and it is internally synchronized, so the per-path receive goroutines share it.
	reflector *telemetry.Reflector

	mu        sync.Mutex
	paths     []*pathState
	sendCodec *frame.Codec
	virt      *udpEndpoint
	// deferred holds the configured paths whose well-formed source_addr was not yet
	// assignable at the last Open (EADDRNOTAVAIL). They are NOT in m.paths or the
	// scheduler — the tunnel runs on the paths that bound — but are recorded here,
	// index-independent of m.paths, for the T55 background reconcile to retry as their
	// addresses appear. Rebuilt from scratch on every Open; guarded by m.mu.
	deferred []deferredPath
	// defaultRemote is the fallback per-path remote (the peer's wireguard
	// endpoint) applied to any path without its own dest_addr. It may be set by
	// ParseEndpoint BEFORE Open, so it is stored here and applied at Open time.
	defaultRemote    netip.AddrPort
	hasDefaultRemote bool

	outerSeq atomic.Uint64

	// resequencer is the shared T18 receive resequencing buffer. Every path's
	// decoded DATA frame is pushed through it (by outer-seq) and delivered up the
	// WG path IN ORDER, so WG's inner anti-replay window never sees multipath
	// reorder. It is (re)created per Open — matching the socket lifecycle, and
	// re-pinning its release point after a reconnect — and published atomically so
	// the per-path receive goroutines read it WITHOUT m.mu, preserving T12's
	// lock-free receive fast path. Its own mutex is disjoint from m.mu, so it adds
	// no contention to Send and is never held across a syscall. PROBE handling
	// (T37) never touches it.
	resequencer atomic.Pointer[reseq.Resequencer]

	// FEC datapath (T24). fecCfg is the fixed-ratio Reed-Solomon configuration, nil
	// when FEC is disabled — in which case the whole plane is inert and the datapath
	// is byte-for-byte the pre-T24 behaviour. fecSend (the send-side encoder + parity
	// counters) is (re)built per Open and accessed only under m.mu — on the Send path
	// and the single deadline-tick goroutine (which TryLocks). fecRecv (the receive-
	// side recovery decoder, self-guarded) is published atomically like resequencer so
	// the per-path readLoop goroutines read it WITHOUT m.mu, preserving the lock-free
	// receive fast path. Both are nil/empty when FEC is off. See fec.go.
	fecCfg  *fec.Config
	fecSend *fecSender
	fecRecv atomic.Pointer[fecReceiver]

	// adaptiveCfg is the adaptive-FEC controller configuration (T29), nil in fixed-ratio
	// mode. When both fecCfg and adaptiveCfg are non-nil, Open builds one adaptivefec
	// Controller per span and attaches it to fecSend; the FEC tick loop then drives it
	// from the measured per-path loss and resizes the encoder's per-group parity. It is
	// immutable after construction, so the send/receive hot paths read it without a lock.
	adaptiveCfg *adaptivefec.Config

	// Receive fan-in (T30). To let a path be added at runtime WITHOUT the engine
	// spawning a new receive goroutine (it only builds its receive goroutines once,
	// from the ReceiveFuncs Open returns), the per-path socket reads are decoupled
	// from the engine-facing delivery: the Bind owns one readLoop goroutine PER path
	// (tracked by readersWG) that reads its socket and feeds the shared resequencer,
	// and Open returns a SINGLE engine-facing ReceiveFunc that drains the resequencer
	// in order. A reader pokes deliverSignal after each datagram so the drainer wakes;
	// recvClosed is closed by Close to release both the drainer and any reader parked
	// on a delivery. openPort mirrors Open's bind port so a runtime-added path binds
	// consistently; nextPathID is a monotonic high-water that persists ACROSS Open
	// spans (a Close->Open never lowers it; only a process restart resets it), so a
	// surviving path is never renumbered and a freed id is never reused for the
	// process lifetime, and thus can never collide with the peer's per-path reflector
	// state.
	deliverSignal chan struct{}
	recvClosed    chan struct{}
	readersWG     sync.WaitGroup
	openPort      uint16
	nextPathID    uint16

	// Receive-path liveness sweep (T39, defect D15). Liveness DOWN-detection normally
	// rides StartProbeLoop's single wall-clock ticker goroutine (emitProbes → Tick).
	// Under heavy CPU load — e.g. the concentrator absorbing a saturating forward flood
	// on 4 vCPU — that timer goroutine can be scheduled with ~1s jitter, delaying a
	// path-DOWN transition (and thus the reply-direction failover) past the P1 budget.
	// The per-path receive goroutines, in contrast, are the goroutines the inbound
	// traffic is ALREADY scheduling, so driving Tick from them re-evaluates liveness
	// even when the timer goroutine is starved. sweepIntervalNanos is the probe
	// interval (0 until StartProbeLoop arms it — a bind without the probe transport
	// never sweeps); lastSweepNanos is the wall-clock high-water throttling the sweep
	// to at most once per interval so the receive hot path stays cheap.
	sweepIntervalNanos atomic.Int64
	lastSweepNanos     atomic.Int64
}

// compile-time proof that Multipath satisfies the engine's Bind contract.
var _ Bind = (*Multipath)(nil)

// NewMultipath returns a closed multipath Bind over the configured paths; call
// Open to bind the per-path sockets. The PSK keys the outer framing and must be
// set (config validation guarantees it). The scheduler is the injected send-side
// path-selection policy (T15) whose priority order MUST match the paths slice
// order (index 0 = the preferred primary); it is a required collaborator so the
// send path is never without a policy.
//
// probers is the per-path probe initiator that drives on-wire liveness (T13/T37).
// When non-nil it MUST hold exactly one *telemetry.Prober per path, in path order,
// and those SAME values MUST be the scheduler's PathHealth sources so the liveness
// the probe loop measures is the liveness the scheduler selects on. Pass nil to
// run the bind without the probe transport (the T12 unit tests drive selection via
// sched.AlwaysUp instead). A Reflector is built from the PSK to answer peer probes.
//
// newProber is the factory the runtime path-add path (AddPath, T30) uses to mint a
// prober for a newly-admitted path; it must be non-nil to allow AddPath and MUST be
// paired with a non-nil probers (the boot-time set) — a factory without a boot-time
// slice would let AddPath append to a nil m.probers, breaking the m.paths/m.probers
// alignment invariant and panicking on the next Open at m.probers[i]. Pass nil to
// forbid runtime path addition.
//
// fecCfg is the fixed-ratio Reed-Solomon FEC configuration (T24). Pass nil to run the
// datapath with FEC disabled (the pre-T24 behaviour, byte-for-byte); a non-nil,
// pre-validated config turns the send-side parity encoder and receive-side recovery
// decoder on. It is validated here (fail fast) so an invalid ratio is rejected at
// construction rather than at the first Open.
// adaptiveCfg is the adaptive-FEC controller configuration (T29). Pass nil for the
// fixed-ratio behaviour (T24); a non-nil config REQUIRES a non-nil fecCfg (the
// controller resizes the FEC encoder's parity — it is meaningless with the plane off)
// and reinterprets fecCfg.ParityShards as the controller's parity ceiling. It is
// validated here (fail fast) so a mis-tuned control law is rejected at construction.
//
// amnezia is the tunnel's AmneziaWG obfuscation profile (config.Amnezia). It
// parameterizes the send-path frame-type classifier so a WireGuard control frame is
// recognised and pacing-exempted under advanced security — custom magic headers and
// handshake junk prefixes — as well as in vanilla mode (defect D22). Pass the zero value
// for a vanilla (unobfuscated) tunnel; the classifier then uses the default type words
// and no junk prefix. It does NOT need to match the config's validated state — an
// all-zero profile is exactly the vanilla classifier.
func NewMultipath(paths []config.Path, psk config.Key, scheduler sched.Scheduler, probers []*telemetry.Prober, newProber ProberFactory, fecCfg *fec.Config, adaptiveCfg *adaptivefec.Config, amnezia config.Amnezia) (*Multipath, error) {
	if len(paths) == 0 {
		return nil, errors.New("bind: at least one path is required")
	}
	if !psk.IsSet() {
		return nil, errors.New("bind: PSK is required for outer framing")
	}
	if len(paths) > 256 {
		// path-id is a uint8 in the DATA frame header.
		return nil, fmt.Errorf("bind: at most 256 paths supported, got %d", len(paths))
	}
	if scheduler == nil {
		return nil, errors.New("bind: a send scheduler is required")
	}
	if newProber != nil && probers == nil {
		// A runtime-path factory without a boot-time prober slice would let AddPath append
		// to a nil m.probers, desyncing m.paths from m.probers and panicking on the next
		// Open at m.probers[i]. The two are paired by construction; enforce it here.
		return nil, errors.New("bind: newProber requires a non-nil probers (boot-time set)")
	}
	if probers != nil && len(probers) != len(paths) {
		return nil, fmt.Errorf("bind: probers must have one entry per path (got %d, want %d)", len(probers), len(paths))
	}
	for i, pr := range probers {
		if pr == nil {
			return nil, fmt.Errorf("bind: prober %d is nil", i)
		}
	}
	if fecCfg != nil {
		if err := fecCfg.Validate(); err != nil {
			return nil, fmt.Errorf("bind: invalid FEC configuration: %w", err)
		}
		if fecCfg.Deadline > maxFECDeadline {
			// A deadline this large makes every deadline-flushed group's recovery
			// structurally late: the resequencer skips the gap (resequencerTimeout) before
			// the parity-derived frames land, so recovery never delivers. Reject it rather
			// than ship a bond whose FEC silently cannot help (defect #4).
			return nil, fmt.Errorf("bind: fec deadline %s exceeds the max %s (must stay safely below the resequencer's %s per-gap timeout so deadline-flushed recovery lands before the gap is skipped)", fecCfg.Deadline, maxFECDeadline, resequencerTimeout)
		}
	}
	if adaptiveCfg != nil {
		if fecCfg == nil {
			return nil, errors.New("bind: adaptive FEC requires a FEC configuration (the controller resizes the FEC encoder's parity)")
		}
		if err := adaptiveCfg.Validate(); err != nil {
			return nil, fmt.Errorf("bind: invalid adaptive FEC configuration: %w", err)
		}
		// The controller's parity ceiling (MaxParity) is the fixed FEC ParityShards both
		// ends agree on: the receiver's decoder is built at fecCfg.ParityShards, and the
		// encoder must never emit more parity than that ceiling (SetParity clamps to it).
		// A mismatch would let the controller target a parity index the decoder rejects,
		// so bind the two together at construction rather than trusting the caller.
		if adaptiveCfg.MaxParity != fecCfg.ParityShards {
			return nil, fmt.Errorf("bind: adaptive FEC parity ceiling (MaxParity=%d) must equal the FEC parity_shards (%d), which the receiver's decoder is built at", adaptiveCfg.MaxParity, fecCfg.ParityShards)
		}
		if adaptiveCfg.DataShards != fecCfg.DataShards {
			return nil, fmt.Errorf("bind: adaptive FEC DataShards (%d) must equal the FEC data_shards (%d)", adaptiveCfg.DataShards, fecCfg.DataShards)
		}
	}
	return &Multipath{
		psk:            psk,
		defs:           append([]config.Path(nil), paths...),
		scheduler:      scheduler,
		classify:       newWGClassifier(amnezia),
		probers:        probers,
		newProber:      newProber,
		deferredListen: defaultDeferredListen,
		reflector:      telemetry.NewReflector(psk, rand.Reader),
		virt:           &udpEndpoint{},
		fecCfg:         fecCfg,
		adaptiveCfg:    adaptiveCfg,
	}, nil
}

// Open binds one UDP socket per configured path to that path's source address on
// port (0 = random per socket), sets a large SO_RCVBUF on each, spawns one
// Bind-owned reader per path, and returns a SINGLE engine-facing ReceiveFunc (the
// fan-in drainer) plus the first path's bound port. Each path whose config carries
// a dest_addr — or, failing that, the peer's wireguard endpoint learned via
// ParseEndpoint — starts with a known remote; the rest are learned from inbound
// traffic.
//
// Open is the sole creator of the per-path sockets: the engine's bring-up path
// calls Close() first (on the still-unopened bind) and then Open(), so building
// the sockets HERE — not in NewMultipath — is what makes that Close→Open sequence
// (and every subsequent Down→Up) work. The engine passes the previously-bound
// port back on a re-Open; each path binds to it on its own distinct source
// address, and the first path's bound port is returned so the engine keeps a
// stable listen port across the cycle (matching conn.StdNetBind).
func (m *Multipath) Open(port uint16) ([]ReceiveFunc, uint16, error) {
	m.mu.Lock()
	defer m.mu.Unlock()
	if len(m.paths) != 0 {
		return nil, 0, conn.ErrBindAlreadyOpen
	}

	sendCodec, err := frame.NewCodec(m.psk)
	if err != nil {
		return nil, 0, err
	}

	// A fresh resequencer per Open: its release point re-pins to the first frame
	// received after this bring-up, so a Close→Open cycle (or reconnect) never
	// wedges on a stale high-water outer-seq.
	m.resequencer.Store(reseq.New(resequencerWindow, resequencerTimeout, reseq.SystemClock{}))

	// Fresh FEC send/receive state per Open, when FEC is enabled (T24). The encoder
	// group state and the decoder's per-group buffers re-pin with the sockets, so a
	// Close→Open cycle never reconstructs against a stale group. Both are torn down in
	// closeSocketsLocked. A build error here is a programmer error (the ratio was
	// validated in NewMultipath), so it fails the Open.
	if m.fecCfg != nil {
		enc, err := fec.NewEncoder(*m.fecCfg, fec.SystemClock{})
		if err != nil {
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: build FEC encoder: %w", err)
		}
		dec, err := fec.NewDecoder(*m.fecCfg)
		if err != nil {
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: build FEC decoder: %w", err)
		}
		dec.SetRetainWindow(fecRetainGroups)
		// Quiescence-accurate unrecoverable accounting (D24): fold a doomed group into
		// the unrecoverable counter once its recovery could no longer have helped, even
		// when no newer group arrives to advance the retain-window eviction (a stalled
		// link, or traffic that simply stops after an incident). Past fecRecoveryDeadline
		// from a group's first-seen instant, its deadline-flushed parity has certainly
		// arrived (encoder grouping deadline) AND the resequencer has certainly skipped
		// its gap (resequencerTimeout), so any later reconstruction is delivered too late
		// to matter — the group is definitively unrecoverable and safe to count.
		dec.SetClock(fec.SystemClock{})
		dec.SetRecoveryDeadline(m.fecCfg.Deadline + resequencerTimeout)
		m.fecSend = &fecSender{enc: enc}
		// Adaptive mode (T29): a fresh controller per Open, re-pinned with the encoder so a
		// Close→Open cycle starts the control law from M=0 (no standing redundancy until
		// loss is observed) rather than inheriting a stale target. The controller cfg was
		// validated in NewMultipath, so a build error here is a programmer error and fails
		// the Open. The receive-side residual-loss estimator (post-FEC-recovery loss, the
		// P4 signal) is likewise fresh per span.
		if m.adaptiveCfg != nil {
			ctrl, err := adaptivefec.NewController(*m.adaptiveCfg, adaptivefec.SystemClock{})
			if err != nil {
				_ = m.closeSocketsLocked()
				return nil, 0, fmt.Errorf("bind: build adaptive FEC controller: %w", err)
			}
			m.fecSend.ctrl = ctrl
			// Adopt the controller's starting parity (0 — no standing redundancy until loss
			// is observed) so the encoder and controller agree from t=0; the tick loop then
			// sizes it to measured loss within the first control interval. Fixed mode leaves
			// the encoder at its cfg.ParityShards default instead.
			enc.SetParity(ctrl.Parity())
		}
		m.fecRecv.Store(&fecReceiver{dec: dec, connLoss: telemetry.NewConnLoss(fecResidualLossWindow)})
	}

	// Resolve every path's interface up front and decide, per path, whether its
	// socket may be device-bound (SO_BINDTODEVICE + wildcard — survives a T16
	// re-roam) or must pin the specific source IP (the pre-T16 behaviour, required
	// when paths share an interface or the interface is multi-address, so distinct
	// specific-IP sockets coexist on one port without an EADDRINUSE collision). See
	// selectDeviceBinds.
	srcs := make([]netip.Addr, len(m.defs))
	for i := range m.defs {
		srcs[i] = m.defs[i].SourceAddr
	}
	bindDevs := planPathBinds(srcs)

	// A path whose WELL-FORMED source_addr is merely NOT-YET-ASSIGNABLE at boot
	// (EADDRNOTAVAIL: no interface holds the address — a 5G modem without a DHCP
	// lease, Starlink mid-obstruction) is DEFERRED rather than treated as fatal, so
	// the bond comes up on the paths that DO bind (G2/W1, approach A). Tolerating it
	// requires the runtime path-down machinery: the deferred path's prober stays
	// StateDown so the scheduler excludes it, and a DynamicScheduler whose membership
	// can be reconciled to only the bound paths. Absent the probe transport (the T12
	// no-prober unit binds) or a dynamic scheduler there is no such Down model, so —
	// exactly as AddPath refuses a runtime add without probers — every bind error
	// stays fatal there. A MALFORMED source_addr never reaches here (config.validate
	// rejects it at load), and any OTHER bind error (EADDRINUSE, permission) is fatal.
	dyn, dynOK := m.scheduler.(sched.DynamicScheduler)
	tolerateDefer := m.probers != nil && dynOK
	m.deferred = nil

	actualPort := port
	firstBound := true
	// boundProbers is index-aligned with m.paths (the paths that actually bound), so
	// the scheduler reconcile below and Send's Pick->m.paths[idx] mapping stay aligned
	// even when a middle path deferred. nil in the no-prober case (nothing to reconcile).
	var boundProbers []*telemetry.Prober
	for i := range m.defs {
		def := m.defs[i]
		// Device-bind this path when selectDeviceBinds proved it safe (so a
		// mid-session source-address change / T16 re-roam does not break the socket),
		// otherwise pin the specific source IP. See selectDeviceBinds / listenPath.
		c, err := listenPath(def.SourceAddr, port, bindDevs[i])
		if err != nil {
			if tolerateDefer && errors.Is(err, syscall.EADDRNOTAVAIL) {
				// Defer this path: record its def + boot prober (kept Down) for the T55
				// background reconcile to retry, and leave the bond to come up on the rest.
				// Mirrors AddPath's rollback discipline — a failed path never disturbs the
				// tunnel — at the boot boundary.
				m.deferred = append(m.deferred, deferredPath{def: def, prober: m.probers[i]})
				continue
			}
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: open path %q on %s: %w", def.Name, def.SourceAddr, err)
		}
		// Large SO_RCVBUF, best-effort: the kernel caps at net.core.rmem_max and
		// SetReadBuffer does not require privilege, so a returned error is rare;
		// treat it as non-fatal rather than refusing to bind in a restricted env.
		_ = c.SetReadBuffer(socketRecvBuffer)

		codec, err := frame.NewCodec(m.psk)
		if err != nil {
			_ = c.Close()
			_ = m.closeSocketsLocked()
			return nil, 0, err
		}

		ps := &pathState{name: def.Name, id: uint8(i), src: def.SourceAddr, conn: c, codec: codec}
		if m.probers != nil {
			ps.prober = m.probers[i]
			// Reconcile the DATA-frame path-id to the prober's IMMUTABLE stamp rather than
			// to the slice index i: after a runtime RemovePath the survivor keeps its
			// original (higher) stamp, so index-based numbering would renumber a live path
			// AND diverge its DATA id from its PROBE stamp. Taking id from the prober keeps
			// DATA and PROBE agreeing on the wire and a survivor's id stable across a reopen.
			ps.id = ps.prober.PathID()
			boundProbers = append(boundProbers, ps.prober)
		}
		switch {
		case def.DestAddr.IsValid():
			ps.setRemote(def.DestAddr)
		case m.hasDefaultRemote:
			ps.setRemote(m.defaultRemote)
		}
		m.paths = append(m.paths, ps)
		if firstBound {
			actualPort = uint16(c.LocalAddr().(*net.UDPAddr).Port)
			firstBound = false
		}
	}

	// Hard guard (a): a bond with NO transport is impossible. If every configured path
	// deferred, tolerance must NOT degrade to a zero-path bind — fail fatally, exactly
	// as the pre-tolerance Open did when the sole path could not bind.
	if len(m.paths) == 0 {
		_ = m.closeSocketsLocked()
		return nil, 0, fmt.Errorf("bind: no configured path could bind its source address (all %d deferred as not-yet-assignable)", len(m.deferred))
	}

	// nextPathID is a MONOTONIC HIGH-WATER carried ACROSS Open spans, never decreased.
	// Close does not reset it, and here it is only ever RAISED to at least max(existing
	// path stamp)+1. Resetting it to len(m.paths) (the pre-fix behaviour) re-minted an id
	// a survivor still held once a RemovePath had opened a gap in the stamp space below
	// that survivor's stamp: the next runtime AddPath then collided with the live path at
	// an identical (PathID, SessionID), and because the peer's Reflector keys anti-replay
	// AND the session challenge PER PathID, the strict-monotonic replay filter dropped one
	// of the two independent ProbeSeq streams -> probe loss / false-DOWN. Deriving the
	// high-water from the (prober-stamped) ps.id covers both the probe-transport case and
	// the T12 no-prober case (where ps.id == i, so the high-water is len(m.paths)).
	m.openPort = port
	for _, ps := range m.paths {
		if uint16(ps.id)+1 > m.nextPathID {
			m.nextPathID = uint16(ps.id) + 1
		}
	}
	// A DEFERRED path's boot prober already OWNS its path-id stamp; raise the
	// high-water past it too, so a runtime AddPath arriving while the path is still
	// deferred cannot mint that reserved id and collide with it once T55 binds it.
	for _, dp := range m.deferred {
		if dp.prober != nil {
			if uint16(dp.prober.PathID())+1 > m.nextPathID {
				m.nextPathID = uint16(dp.prober.PathID()) + 1
			}
		}
	}
	m.sendCodec = sendCodec

	// Reconcile the scheduler's membership with the path slice just rebuilt from
	// m.defs. A runtime AddPath/RemovePath (T30) keeps m.defs, m.probers, AND the
	// live scheduler in lockstep during an Open span; re-pinning the scheduler's
	// health list to the BOUND probers HERE — index-aligned with m.paths, since each
	// bound path appended its ps.prober to boundProbers in order above — is the single
	// reconciliation point that makes that runtime membership survive this
	// Close→Open cycle without a scheduler/path desync (no frozen zombie health
	// entry, no resurrected removed path). A DEFERRED path (not-yet-assignable
	// source_addr) is deliberately EXCLUDED here: its prober is absent from the
	// scheduler, so Pick can never select it, and Send's Pick->m.paths[idx] mapping
	// stays index-aligned with the bound-only path slice. Only meaningful with the
	// probe transport: a bind without probers cannot change membership at runtime
	// (AddPath is refused) and never defers, so its scheduler is left exactly as built.
	if m.probers != nil && dynOK {
		health := make([]sched.PathHealth, len(boundProbers))
		for i, pr := range boundProbers {
			health[i] = pr
		}
		if err := dyn.SetPaths(health); err != nil {
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: reconcile scheduler on open: %w", err)
		}
	}

	// Stand up the receive fan-in: one Bind-owned reader per path feeding the shared
	// resequencer, and a single engine-facing drainer. Both channels are recreated
	// per Open so a Close→Open cycle starts clean.
	m.deliverSignal = make(chan struct{}, 1)
	m.recvClosed = make(chan struct{})
	for _, ps := range m.paths {
		m.readersWG.Add(1)
		go m.readLoop(ps, m.deliverSignal)
	}
	// Deadline-tick goroutine for FEC group close (T24): it flushes a partial group's
	// parity on time under low load so a group is never stranded waiting for the size
	// threshold. Tracked by readersWG (like the readers) so Close waits for it; it
	// exits on recvClosed. It TryLocks m.mu, so it never blocks Close's readersWG.Wait
	// held under m.mu.
	if m.fecSend != nil {
		m.readersWG.Add(1)
		go m.fecTickLoop(m.fecCfg.Deadline, m.recvClosed)
	}
	return []ReceiveFunc{m.newReceiveFunc(m.deliverSignal, m.recvClosed)}, actualPort, nil
}

// readLoop is one Bind-OWNED per-path receive goroutine (T30). It reads the path
// socket and dispatches every datagram through handleInbound — which pushes DATA
// into the shared resequencer and answers/consumes PROBEs — then pokes the delivery
// signal so the single engine-facing drainer wakes to release any newly in-order
// frame. The read buffer is private to this goroutine, so the per-path Codec's
// scratch is never shared.
//
// Owning the readers in the Bind (rather than returning one ReceiveFunc per path to
// the engine, as T12 did) is what makes a runtime path add/remove possible without
// disturbing the engine: the engine builds its receive goroutines ONCE from Open's
// return, so a path added later gets a reader HERE while the engine's fixed receive
// set — and thus the WG session — sees no churn. The goroutine exits when its socket
// is closed (RemovePath drains one path; Close drains all).
func (m *Multipath) readLoop(ps *pathState, deliver chan<- struct{}) {
	defer m.readersWG.Done()
	readBuf := make([]byte, maxDatagram)
	for {
		n, srcAP, err := ps.conn.ReadFromUDPAddrPort(readBuf)
		if err != nil {
			return // socket closed: this path was removed, or the bind was closed
		}
		// Per-path received-wire accounting (T23): count the OUTER datagram this path
		// pulled off its socket before dispatch, lock-free. This goroutine is the sole
		// writer of ps.rxBytes, so the atomic Add is uncontended.
		ps.rxBytes.Add(uint64(n))
		m.handleInbound(ps, readBuf[:n], srcAP)
		// Advance liveness off the receive path (throttled): a live signal on THIS path
		// is what lets a DIFFERENT, silent path be marked DOWN promptly even when the
		// probe-loop ticker is starved under load (D15). The peer probes every path
		// (and floods the survivor after it roams), so the surviving path's reader
		// supplies exactly that signal.
		m.tickLivenessFromReceive(time.Now())
		// Non-blocking poke: a single buffered slot coalesces bursts; the drainer
		// re-checks the resequencer on every wake, so a coalesced poke loses nothing.
		select {
		case deliver <- struct{}{}:
		default:
		}
	}
}

// tickLivenessFromReceive re-evaluates EVERY path's liveness from a receive
// goroutine, throttled to at most once per probe interval (T39, defect D15). It is
// the starvation-robust companion to StartProbeLoop's timer-driven Tick: the timer
// goroutine can be delayed ~1s under CPU saturation, but the receive goroutines are
// scheduled by the very traffic that must trigger failover, so liveness advances
// regardless. Ticking is monotone-safe: Tick only marks an UP path DOWN once its
// silence STRICTLY exceeds DownAfter and never brings a path UP (that needs
// RecordEcho), so a more frequent Tick can only make a genuine DOWN transition land
// sooner — never a premature/false one — and the failback hysteresis (owned by the
// scheduler) is untouched. No-op when the probe transport is absent (interval unset).
func (m *Multipath) tickLivenessFromReceive(now time.Time) {
	interval := m.sweepIntervalNanos.Load()
	if interval == 0 {
		return // no probe transport / loop not started: nothing to Tick
	}
	n := now.UnixNano()
	last := m.lastSweepNanos.Load()
	if n-last < interval {
		return // throttled: this interval's sweep was already taken
	}
	if !m.lastSweepNanos.CompareAndSwap(last, n) {
		return // another receive goroutine won this interval's sweep
	}
	// Snapshot the prober set under m.mu (a runtime AddPath/RemovePath mutates it),
	// then Tick OUTSIDE the lock so a transition's log write never runs under m.mu.
	// TryLock, NOT Lock: Close holds m.mu WHILE it waits on readersWG for the readers to
	// exit, so a reader that BLOCKED here on m.mu would deadlock that shutdown. The sweep
	// is opportunistic and throttled, so when the lock is contended (a concurrent
	// Close/AddPath/RemovePath/Send) simply skipping this interval is harmless — the
	// probe-loop ticker and the next receive still advance liveness. This preserves
	// Close's invariant that a reader never blocks on m.mu. The lock, when taken, is held
	// at most once per interval (~5/s) for a bounded snapshot, so it adds negligible
	// contention to Send and does not disturb the lock-free receive fast path.
	if !m.mu.TryLock() {
		return
	}
	probers := make([]*telemetry.Prober, 0, len(m.paths))
	for _, ps := range m.paths {
		if ps.prober != nil {
			probers = append(probers, ps.prober)
		}
	}
	m.mu.Unlock()
	for _, pr := range probers {
		pr.Tick()
	}
	// Eager failover nudge (defect D18, the repeated-flap wedge). The active-backup
	// selection is otherwise recomputed ONLY inside the scheduler's Pick, which the
	// Bind calls ONLY from Send — so failover is pull-based: it happens only when the
	// engine hands down an egress datagram. When the ACTIVE path dies during an egress
	// LULL that is fatal: a repeated-flap kill landing on the just-restored primary
	// before the saturating flow re-fills it (the failback and the next kill overlap)
	// leaves both TCP directions stalled on the now-dead path, so NO Send occurs, so
	// Pick is never called, so egress is never switched to the healthy backup — the
	// bond wedges on the dead path until the 25s WG keepalive finally drives a Send.
	// The receive tick is the starvation-robust signal that ALREADY detected the DOWN
	// (it just Ticked the path down above); recomputing the scheduler from it makes the
	// switch EAGER — bounded by the detection window (~DownAfter + one interval) rather
	// than by the next application Send. Pick recomputes purely against current liveness
	// and the clock and the failback dwell is time-based, so a more frequent recompute
	// can only make a genuine transition land sooner — never a premature/false failover,
	// and never a shortened anti-thrash hysteresis. It takes ONLY the scheduler's own
	// lock (never m.mu), so it adds no receive-path m.mu contention and cannot invert
	// the Send-path m.mu→scheduler lock order.
	m.nudgeSchedulerActive()
}

// nudgeSchedulerActive forces the scheduler to recompute its active egress path
// against current liveness, independent of any application Send. It is the eager-
// failover companion to the Send-driven Pick: driven from the liveness-detection
// paths (the receive tick and the probe loop) it switches egress to a healthy backup
// the moment the active path is detected DOWN, so a dead active path with stalled
// egress does not wedge the bond until the next Send (defect D18). The returned index
// is intentionally discarded — only the recompute (and its logged transition) is
// wanted here; Send remains the sole reader of the selection for actual routing. Pick
// is internally synchronized and never calls back into the Bind, so this is safe to
// call from a receive goroutine or the probe loop without m.mu.
//
// It calls Recompute, NOT Pick: the nudge wants only the liveness-driven active-set
// recompute (and its logged transition), and a weighted/aggregating scheduler's Pick
// is STATEFUL — a spurious Pick here would consume a distribution slot and skew the
// per-path weight split. Recompute is the non-consuming half that refreshes the
// eligible/active set without touching distribution/pacing/load state, so the T40
// eager-failover guarantee holds for BOTH the active-backup and the weighted policy
// (defect D18).
func (m *Multipath) nudgeSchedulerActive() {
	m.scheduler.Recompute()
}

// newReceiveFunc returns the SINGLE engine-facing ReceiveFunc: it drains the shared
// resequencer in outer-seq order and hands each inner datagram up under the one
// virtual endpoint. Because every path's reader feeds this one drainer, a path added
// or removed at runtime needs no change to the engine's receive set. When nothing is
// ready it parks until a reader pokes deliver, until Close closes closed, or until a
// short poll elapses — the poll guarantees a head-of-line-blocked run still makes
// timeout progress even if the last live path fell silent right after buffering it.
// A single drainer also delivers with ZERO added reorder (only it calls Pop), which
// is stricter than T12's per-path receivers.
func (m *Multipath) newReceiveFunc(deliver <-chan struct{}, closed <-chan struct{}) ReceiveFunc {
	// One reusable poll timer per drainer, NOT a fresh time.After timer per park: the
	// drainer parks on every empty receive, and a per-park 250 ms timer — retained by
	// the runtime timer heap until it fires even after the park is over — added
	// avoidable allocation and GC pressure on the receive hot path (opus low defect).
	// The ReceiveFunc is driven by a single engine goroutine, so the timer has no
	// concurrent user; Stop+drain then Reset per park reuses the one allocation.
	timer := time.NewTimer(resequencerTimeout)
	stopTimer := func() {
		timer.Stop()
		select {
		case <-timer.C:
		default:
		}
	}
	stopTimer() // start inert; armed only while parked
	return func(packets [][]byte, sizes []int, eps []Endpoint) (int, error) {
		for {
			// Deliver any in-order resequenced DATA. The item carries the outer source
			// of the frame that produced it, so the virtual endpoint pins correctly even
			// when the frame was buffered and released out of arrival order.
			if it, ok := m.resequencer.Load().Pop(); ok {
				if len(it.Payload) > len(packets[0]) {
					continue // oversize inner datagram: drop, keep draining
				}
				sizes[0] = copy(packets[0], it.Payload)
				eps[0] = m.virtualEndpoint(it.Src)
				return 1, nil
			}
			timer.Reset(resequencerTimeout)
			select {
			case <-deliver:
				stopTimer()
			case <-timer.C:
				// Poll fired; its channel is already drained by this receive.
			case <-closed:
				stopTimer()
				return 0, errClosed
			}
		}
	}
}

// handleInbound decodes one received outer datagram and dispatches it by kind. It
// is the single per-frame receive action, factored out of readLoop so the probe
// transport is exercisable without spinning receive goroutines. Delivery up the WG
// path is deferred to the resequencer (Pop, in the engine-facing drainer): a DATA
// frame is not handed up here but pushed into the shared resequencer to be released in
// outer-seq order.
//
//   - DATA: the decoded inner datagram is pushed into the resequencer keyed by
//     the frame's outer-seq (delivered later, in order, via Pop). The path's
//     remote is NOT learned here — remote-learning is authenticated-only (see
//     below), so a forged DATA frame cannot steer a path's return endpoint.
//   - PROBE, IsEcho=false: an authenticated peer probe. Its source is learned as
//     the path's remote (D11: a probe-only backup path gets a usable return remote
//     before any DATA flows) and it is reflected straight back to that source via
//     this path's socket (T13 Reflector). Reflection writes independently of the
//     scheduler/getRemote so an echo returns even on a not-yet-active path.
//   - PROBE, IsEcho=true: an authenticated echo of one of our own probes. Its
//     source is learned as the remote too, and the raw echo is fed into this
//     path's Prober (HandleEcho) to update RTT/loss and drive liveness.
//   - anything else (PARITY/CONTROL/malformed): dropped.
//
// Remote-learning and reflection touch only authenticated (MAC-verified) PROBE
// frames — Decode has already verified the tag for the PROBE kind — which is what
// resolves D9: an attacker who forges an unauthenticated DATA frame can no longer
// repoint a path's return endpoint.
//
// FEC seam (T24): DATA ingestion via resequencer.Observe is keyed purely on
// outer-seq, so an FEC decoder can slot in BEFORE the resequencer with no change
// here — PARITY (dropped today) will feed the decoder, which reconstructs missing
// DATA frames and calls Observe with their ORIGINAL outer-seq, identical to a
// natively-received frame.
func (m *Multipath) handleInbound(ps *pathState, raw []byte, srcAP netip.AddrPort) {
	fr, err := ps.codec.Decode(raw)
	if err != nil {
		return // drop malformed / PSK-mismatched outer frames
	}
	switch f := fr.(type) {
	case frame.Data:
		// Decode already returned a fresh copy of the payload (it aliases nothing
		// else), so the resequencer may take ownership of it directly.
		rq := m.resequencer.Load()
		if fr := m.fecRecv.Load(); fr != nil {
			// FEC on (T24): offer the data shard to the decoder BEFORE resequencing so a
			// later parity frame can reconstruct any group-mate lost in transit, then
			// deliver THIS received frame in its own right (the decoder never echoes a
			// directly-received data shard back). The shard's coded bytes are
			// OuterSeq || Payload — the same bytes the sender coded parity over.
			shard := fec.DataShard{Group: fec.GroupID(f.FECGroup), Index: int(f.FECIndex), Payload: fecShardPayload(f.OuterSeq, f.Payload)}
			recovered, _ := fr.offer(shard)
			rq.Observe(f.OuterSeq, f.Payload, srcAP)
			// Residual-loss accounting (T29): this outer-seq was natively delivered, so mark
			// it present in the post-recovery loss estimator. A seq never marked here nor via
			// a reconstruction below is loss that FEC did not mask.
			if fr.connLoss != nil {
				fr.connLoss.Observe(f.OuterSeq)
			}
			m.observeRecovered(fr, rq, recovered, srcAP)
		} else {
			rq.Observe(f.OuterSeq, f.Payload, srcAP)
		}
	case frame.Parity:
		// PARITY feeds the FEC decoder (T24); a group that has now accumulated enough
		// shards reconstructs its missing data frames, each resequenced at its ORIGINAL
		// outer-seq (carried in the recovered shard's coded bytes) so recovery composes
		// with T18 exactly like a natively-received frame. With FEC off, PARITY is
		// dropped (the pre-T24 behaviour).
		if fr := m.fecRecv.Load(); fr != nil {
			shard := fec.ParityShard{Group: fec.GroupID(f.FECGroup), Index: int(f.ParityIndex), DataCount: int(f.DataCount), Payload: f.Payload}
			recovered, _ := fr.offer(shard)
			m.observeRecovered(fr, m.resequencer.Load(), recovered, srcAP)
		}
	case frame.Probe:
		// Authenticated (the PROBE MAC verified in Decode): learn the return remote
		// from it, below the engine's virtual endpoint (no roaming churn).
		ps.setRemote(srcAP)
		if f.IsEcho {
			if ps.prober != nil {
				// A replay/forgery/wrong-path echo is rejected inside HandleEcho and
				// leaves liveness untouched; the error is a per-frame drop, not fatal.
				// ps.prober is the path's OWN immutable prober — never a lookup into a
				// dynamically-mutated slice — so runtime add/remove cannot race this.
				_ = ps.prober.HandleEcho(raw)
			}
			return
		}
		if m.reflector != nil {
			if echo, rerr := m.reflector.Reflect(raw); rerr == nil {
				// UDP writes are goroutine-safe, so this receive-goroutine reflection
				// races no in-flight Send on the same socket.
				_, _ = ps.conn.WriteToUDPAddrPort(echo, srcAP)
			}
		}
	default:
		// CONTROL (and any unhandled kind) is not delivered up this path.
	}
}

// observeRecovered feeds every FEC-reconstructed data frame into the resequencer at
// its ORIGINAL outer-seq (recovered from the shard's coded bytes) via the NON-resyncing
// ObserveRecovered path, so a frame rebuilt from parity resequences identically to a
// natively-received frame — filling the exact gap the resequencer would otherwise time
// out on — WITHOUT a late batch of recovered seqs being able to move the release point
// or dump the live buffer (recovery must never cause loss). Only frames actually placed
// AHEAD of the release point advance the honest delivered-recovery counter; a frame
// rebuilt after the resequencer already skipped its gap is dropped as late and not
// counted, so /metrics reflects delivered recovery, not mere reconstruction. A
// malformed recovered shard (too short to hold the outer-seq prefix) is dropped: it
// signals an encoder/decoder mismatch, not a deliverable frame.
func (m *Multipath) observeRecovered(fr *fecReceiver, rq *reseq.Resequencer, recovered []fec.Recovered, srcAP netip.AddrPort) {
	for _, rec := range recovered {
		seq, inner, err := splitFECShardPayload(rec.Payload)
		if err != nil {
			continue
		}
		// Residual-loss accounting (T29): FEC reconstructed this outer-seq, so it is NOT
		// residual loss — mark it present in the post-recovery estimator even if the
		// resequencer later drops it as late (that is a latency outcome, not a masking
		// failure; the P4 residual bound measures loss FEC failed to mask).
		if fr.connLoss != nil {
			fr.connLoss.Observe(seq)
		}
		if rq.ObserveRecovered(seq, inner, srcAP) {
			fr.deliveredRecovered.Add(1)
		}
	}
}

// virtualEndpoint returns the single stable endpoint the engine holds for the
// peer. On the concentrator (which has no configured endpoint) its destination
// is pinned ONCE to the first learned source; thereafter every path returns the
// identical pointer so the engine sees one peer, never per-packet churn.
//
// Hot-path note: the destination, once pinned, never changes, and it is published
// through an atomic.Pointer (see udpEndpoint). So the common case takes a
// lock-free fast path — every received datagram would otherwise contend m.mu with
// in-flight Sends. The mutex is acquired only to pin the FIRST learned source.
func (m *Multipath) virtualEndpoint(learned netip.AddrPort) Endpoint {
	if m.virt.dstValid() {
		return m.virt
	}
	m.mu.Lock()
	defer m.mu.Unlock()
	if !m.virt.dstValid() {
		m.virt.setDst(learned)
	}
	return m.virt
}

// Send wraps each buffer in an outer DATA frame (fresh outer-seq + the chosen
// path's id) and writes it to that path's remote. The egress path is chosen by
// the injected scheduler (T15): the active-backup policy returns the preferred
// primary while it is up and the failover backup otherwise. The scheduler
// selects by path priority/liveness only; the Bind additionally requires THAT
// ONE chosen path to have a known remote, failing the send otherwise rather
// than silently dropping.
//
// Behavioural change from pre-T15: this is a deliberate NARROWING. The removed
// pickPathLocked iterated the paths and skipped any healthy-but-remoteless one,
// falling through to the next healthy path WITH a known remote, so a send failed
// only when NO path had a remote. Now the scheduler owns selection and returns a
// single index; the Bind does NOT fall through, because a Bind-level fall-through
// would bypass the scheduler's hysteresis (failover/failback). The residual
// window this opens: if the scheduler's chosen path is reported Up but its remote
// is not yet learned — e.g. a concentrator/hub restart, or a T16 NAT-rebind
// before the first inbound packet re-teaches the remote — the send fails until
// that path's remote is learned, even if another path has a known remote.
//
// Critical-section discipline: path selection and framing run under m.mu (the
// send Codec is shared and stateful — D5's single keystream requires sequential,
// mutex-guarded Encode), but each datagram is encoded into its OWN fresh buffer
// so it outlives the lock, and the WriteToUDPAddrPort syscalls run WITHOUT m.mu
// held. The scheduler is internally synchronized and never calls back into the
// Bind, so calling Pick under m.mu cannot deadlock and adds no receive-path
// contention (the lock-free virtual-endpoint fast path is untouched). A receive
// goroutine pinning the virtual endpoint therefore never blocks behind an
// in-flight transmit syscall.
func (m *Multipath) Send(bufs [][]byte, ep Endpoint) error {
	if _, ok := ep.(*udpEndpoint); !ok {
		return conn.ErrWrongEndpointType
	}

	// Classify the batch by inner WireGuard message type (defect D22): a handshake or
	// keepalive is passed to the scheduler as ClassControl so a pacing scheduler exempts
	// it from the per-path data token buckets and bulk overload cannot shed it and starve
	// rekey. The classifier is parameterized by the tunnel's Amnezia profile, so it works
	// under advanced-security obfuscation (custom magic headers + handshake junk), not
	// only vanilla WireGuard. It reads only the (possibly junk-shifted) type word off the
	// lock.
	class := m.classify.classifyBatch(bufs)

	m.mu.Lock()
	if len(m.paths) == 0 {
		m.mu.Unlock()
		return errClosed
	}
	idx := m.scheduler.Pick(class)
	if idx == sched.PickPaced {
		// The scheduler shed this datagram for pacing while paths are healthy: drop it
		// (same as no-path), but surface a DISTINCT error so the diagnostic is not
		// conflated with a total outage. The rate-limited log is emitted at the source
		// (the scheduler), so no per-drop logging happens here on the hot path.
		m.mu.Unlock()
		return errPacerShedding
	}
	if idx < 0 || idx >= len(m.paths) {
		m.mu.Unlock()
		return errNoHealthyPath
	}
	ps := m.paths[idx]
	remote, ok := ps.getRemote()
	if !ok {
		m.mu.Unlock()
		return errNoHealthyPath
	}

package frame

import (
	"crypto/hkdf"
	"crypto/hmac"
	"crypto/rand"
	"crypto/sha256"
	"encoding/binary"
	"errors"
	"fmt"

	"golang.org/x/crypto/chacha20"

	"github.com/7mind/wanbond/internal/config"
)

// Wire model (requirement-6 groundwork — no plaintext magic bytes, no fixed
// offsets). Every frame on the wire is:
//
//	nonce[nonceLen] || obf(body) [ || tag[tagLen] ]
//
//   - nonce is nonceLen fresh random bytes (high entropy, never constant).
//   - body is (kind byte || kind-specific header || opaque payload). It is
//     obfuscated by XOR with an XChaCha20 keystream derived from a PSK-bound
//     obfuscation subkey and the per-frame nonce, so the type discriminant and
//     header never sit at a constant offset — a byte-histogram over many random
//     encodings shows no constant byte position.
//   - tag is present ONLY for authenticated kinds (CONTROL, PROBE): an
//     Encrypt-then-MAC HMAC-SHA256 (truncated to tagLen) over nonce||obf(body)
//     keyed by a distinct PSK-bound auth subkey. Decode verifies it and rejects
//     tampered or PSK-mismatched frames. DATA and PARITY are unauthenticated by
//     design (DoS-grade forgery accepted — the inner WireGuard layer
//     authenticates the real payload); they carry no tag but are still
//     keystream-obfuscated so the no-fixed-offset property holds and the peer,
//     sharing the PSK, derives the same keystream to decode them.
//
// The two subkeys are derived from the PSK with HKDF-SHA256 under distinct info
// labels, so the obfuscation stream and the authentication MAC never share key
// material. All primitives are vetted (crypto/hkdf, x/crypto/chacha20,
// crypto/hmac) — no hand-rolled crypto.
//
// The outer-seq DATA field is this codec's OWN sequence space (see
// docs/p0-findings.md §6); it is never the inner WireGuard counter, and this
// codec never inspects the opaque WG payload (§4).

const (
	// nonceLen is the XChaCha20 nonce length carried in the clear at the head of
	// every frame.
	nonceLen = chacha20.NonceSizeX // 24
	// tagLen is the truncated HMAC-SHA256 authentication tag length appended to
	// authenticated frames.
	tagLen = 16
	// subkeyLen is the length of each HKDF-derived subkey.
	subkeyLen = 32

	infoObf  = "wanbond outer-frame obfuscation v1"
	infoAuth = "wanbond outer-frame authentication v1"
)

// DataOverhead is the number of bytes a KindData frame adds on top of its opaque
// payload on the wire: the clear nonce plus the DATA header (kind || outer-seq ||
// path-id || fec-group || fec-index || flags). DATA frames are unauthenticated
// (see the wire model above), so they carry no tag; this figure is therefore exact
// and is what the multipath Bind subtracts from the path MTU when sizing the inner
// tunnel (see internal/bind mtu.go). The fec-index byte is carried on every DATA
// frame — 0 and inert when FEC is disabled (T24) — so the codec's wire layout is
// invariant to the FEC toggle.
const DataOverhead = nonceLen + // clear nonce
	1 + // kind discriminant
	8 + // outer-seq (uint64)
	1 + // path-id (uint8)
	4 + // fec-group (uint32)
	1 + // fec-index (uint8): shard position within the FEC group (T24)
	1 // flags (uint8)

// ParityOverhead is the number of bytes a KindParity frame adds on top of its
// shard payload on the wire: the clear nonce plus the PARITY header (kind ||
// fec-group || parity-index || data-count || path-id). PARITY, like DATA, is
// unauthenticated and carries no tag, so this figure is exact. The multipath Bind
// uses it to size the FEC parity-overhead MTU penalty (T24): a full-size parity
// frame is 5 bytes larger on the wire than a full-size DATA frame carrying the same
// inner payload, so with FEC enabled the inner MTU is reduced so BOTH fit the path
// MTU without fragmentation (see internal/bind mtu.go).
const ParityOverhead = nonceLen + // clear nonce
	1 + // kind discriminant
	4 + // fec-group (uint32)
	2 + // parity-index (uint16)
	1 + // data-count (uint8)
	1 // path-id (uint8)

// Kind is the outer frame discriminant. Values are nonzero so a zeroed buffer
// never decodes to a valid kind.
type Kind uint8

const (
	// KindData wraps one opaque WireGuard datagram with multipath/FEC metadata.
	KindData Kind = 1
	// KindParity carries an FEC parity symbol for a fec-group.
	KindParity Kind = 2
	// KindProbe is an authenticated path-probe (RTT / liveness) frame.
	KindProbe Kind = 3
	// KindControl is an authenticated out-of-band control frame.
	KindControl Kind = 4
)

func (k Kind) valid() bool {
	return k == KindData || k == KindParity || k == KindProbe || k == KindControl
}

// authenticated reports whether frames of this kind append (and verify) a MAC.
func (k Kind) authenticated() bool {
	return k == KindProbe || k == KindControl
}

// Frame is the closed sum over the four outer frame kinds. The unexported
// marker method prevents other packages from adding kinds.
type Frame interface {
	// Kind returns the frame's discriminant.
	Kind() Kind
	// appendBody appends the plaintext body (kind byte || header || payload).
	appendBody(dst []byte) []byte
	isFrame()
}

// Data wraps a single opaque WireGuard datagram. OuterSeq is this codec's own
// sequence space (never the inner WG counter); PathID/FECGroup/FECIndex/Flags feed
// the multipath scheduler (T12), FEC (T14/T24), and resequencer (T18). FECIndex is
// the data shard's position within its FEC group (0..M-1); it is 0 and inert when
// FEC is disabled. The receiver reconstructs the FEC data-shard bytes as
// OuterSeq || Payload, so a shard recovered from parity carries its own outer-seq
// (T24) — no separate per-group base state is needed to resequence a recovered
// frame.
type Data struct {
	OuterSeq uint64
	PathID   uint8
	FECGroup uint32
	FECIndex uint8
	Flags    uint8
	Payload  []byte
}

// Parity carries one FEC parity symbol for a fec-group. DataCount is the group
// cardinality M (the number of data shards the parity protects); the decoder learns
// M from any surviving parity frame, so it must ride the wire (T24).
type Parity struct {
	FECGroup    uint32
	ParityIndex uint16
	DataCount   uint8
	PathID      uint8
	Payload     []byte
}

// Probe is an authenticated path probe used for RTT and liveness estimation.
//
// IsEcho is the request/response discriminant. A probe emitted by an originator
// (telemetry.Prober.SendProbe) carries IsEcho=false; the responder reflects it
// verbatim with IsEcho=true (telemetry.Reflector.Reflect). The two are otherwise
// byte-for-body-identical, so the receiving transport needs this bit to route an
// inbound frame: IsEcho=false is a peer probe to REFLECT, IsEcho=true is an echo
// of our own probe to FEED into that path's Prober. Marking the echo also breaks
// the otherwise-unbounded reflect-of-a-reflect loop (an echo is never reflected).
//
// SessionID is the originator's random per-boot session identity (T38, defect
// D12). It sits inside the MAC-covered body (adjacent to IsEcho), so an attacker
// can neither forge nor flip it. The responder reflects it verbatim. It TAGS the
// session (which boot the probe stream belongs to); on its own it is NOT proof of
// freshness (a captured probe carries a "never-seen" SessionID too), so the
// session-epoch reset is gated on the Challenge below, never on the SessionID
// merely being novel.
//
// Challenge is the responder-contributed freshness token (T38 redesign, defect
// D12). Like SessionID it lives inside obf(body) under the MAC, so it is both
// confidential (only a PSK holder can read it) and unforgeable. Its meaning is
// keyed by IsEcho:
//
//   - On an ECHO (IsEcho=true, emitted by the Reflector): Challenge is the
//     responder's CURRENT per-path issued challenge — a fresh random value the
//     originator must echo back to prove liveness.
//   - On a PROBE (IsEcho=false, emitted by the originator): Challenge is the last
//     issued challenge the originator learned from an echo (zero before it has
//     seen any). The responder adopts a new session epoch (resetting its
//     anti-replay high-water) ONLY when this equals its live issued challenge, so
//     a replayed probe — which can never carry the responder's current challenge —
//     can never seize the epoch or lock out the live peer.
type Probe struct {
	PathID         uint8
	ProbeSeq       uint64
	TimestampNanos int64
	IsEcho         bool
	SessionID      uint64
	Challenge      uint64
	Payload        []byte
}

// Control is an authenticated out-of-band control frame.
//
// Seq is a strictly-monotonic per-(peer, ControlType) sequence number: the
// freshness material the STATEFUL control-handling layer (telemetry.ControlGuard)
// uses to reject replays of a security-relevant control message (defect D4). The
// codec (Decode) verifies only the PSK HMAC and keeps no per-peer state, so a
// passively-captured valid control frame — e.g. a rekey — replays with a passing
// MAC; the downstream guard tracks a per-type high-water on Seq and drops the
// replay. Seq rides INSIDE obf(body) under the MAC (like Probe.ProbeSeq), so an
// attacker can neither read it nor forge/advance it to smuggle a replay past the
// guard.
type Control struct {
	ControlType uint8
	Seq         uint64
	Payload     []byte
}

func (Data) isFrame()    {}
func (Parity) isFrame()  {}
func (Probe) isFrame()   {}
func (Control) isFrame() {}

func (Data) Kind() Kind    { return KindData }
func (Parity) Kind() Kind  { return KindParity }
func (Probe) Kind() Kind   { return KindProbe }
func (Control) Kind() Kind { return KindControl }

func (f Data) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindData))
	dst = binary.BigEndian.AppendUint64(dst, f.OuterSeq)
	dst = append(dst, f.PathID)
	dst = binary.BigEndian.AppendUint32(dst, f.FECGroup)
	dst = append(dst, f.FECIndex)
	dst = append(dst, f.Flags)
	return append(dst, f.Payload...)
}

func (f Parity) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindParity))
	dst = binary.BigEndian.AppendUint32(dst, f.FECGroup)
	dst = binary.BigEndian.AppendUint16(dst, f.ParityIndex)
	dst = append(dst, f.DataCount)
	dst = append(dst, f.PathID)
	return append(dst, f.Payload...)
}

func (f Probe) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindProbe))
	dst = append(dst, f.PathID)
	dst = binary.BigEndian.AppendUint64(dst, f.ProbeSeq)
	dst = binary.BigEndian.AppendUint64(dst, uint64(f.TimestampNanos))
	dst = append(dst, boolByte(f.IsEcho))
	dst = binary.BigEndian.AppendUint64(dst, f.SessionID)
	dst = binary.BigEndian.AppendUint64(dst, f.Challenge)
	return append(dst, f.Payload...)
}

// boolByte encodes a bool as a single wire byte (0 or 1).
func boolByte(b bool) byte {
	if b {
		return 1
	}
	return 0
}

func (f Control) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindControl))
	dst = append(dst, f.ControlType)
	dst = binary.BigEndian.AppendUint64(dst, f.Seq)
	return append(dst, f.Payload...)
}

// ErrMalformed is returned by Decode for any input too short or structurally
// invalid to be a frame.
var ErrMalformed = errors.New("frame: malformed input")

// ErrAuth is returned by Decode when an authenticated frame fails its MAC check
// (tampered ciphertext or PSK mismatch).
var ErrAuth = errors.New("frame: authentication failed")

// Codec is a reusable, PSK-bound frame encoder/decoder. It derives the HKDF
// obfuscation and authentication subkeys ONCE at construction and reuses them
// (plus per-call scratch buffers) across every Encode/Decode, and it inits the
// XChaCha20 keystream exactly once per frame. This resolves defect D5: the old
// package-level Encode/Decode re-derived both subkeys with HKDF-SHA256 and
// double-init'd ChaCha20 (once in peekByte, once for the full body) on EVERY
// frame — prohibitive on the per-datagram datapath the multipath Bind drives.
//
// A Codec is NOT safe for concurrent use: its scratch buffers are shared across
// calls. Construct one per goroutine (the Bind gives each per-path receive loop
// its own Codec and guards the shared send Codec with the Bind mutex).
type Codec struct {
	obfKey     []byte
	authKey    []byte
	encScratch []byte // reused body buffer for Encode
	decScratch []byte // reused body buffer for Decode
}

// NewCodec derives the PSK-bound subkeys once and returns a reusable Codec. It
// fails only if the PSK is unset.
func NewCodec(psk config.Key) (*Codec, error) {
	obfKey, authKey, err := subkeys(psk)
	if err != nil {
		return nil, err
	}
	return &Codec{obfKey: obfKey, authKey: authKey}, nil
}

// Encode appends the wire encoding of f to dst and returns the extended slice,
// letting the caller reuse one buffer across sends (pass dst[:0]). It fails only
// if the system CSPRNG is unavailable.
func (c *Codec) Encode(dst []byte, f Frame) ([]byte, error) {
	// Build the plaintext body (kind || header || payload) in reusable scratch.
	c.encScratch = f.appendBody(c.encScratch[:0])
	body := c.encScratch

	start := len(dst)
	dst = append(dst, make([]byte, nonceLen)...)
	nonce := dst[start : start+nonceLen]
	if _, err := rand.Read(nonce); err != nil {
		return nil, fmt.Errorf("frame: read nonce: %w", err)
	}

	// Obfuscate the body in scratch, then append it; a single keystream init.
	obfuscate(c.obfKey, nonce, body)
	dst = append(dst, body...)

	if f.Kind().authenticated() {
		// After the append above, nonce and obfBody are contiguous in dst's
		// (possibly reallocated) backing array; tag over nonce||obfBody.
		nonce = dst[start : start+nonceLen]
		obfBody := dst[start+nonceLen:]
		dst = append(dst, tag(c.authKey, nonce, obfBody)...)
	}
	return dst, nil
}

// Decode parses a wire frame. It verifies the MAC of authenticated frames and
// rejects tampered or PSK-mismatched ones. It never panics on malformed input.
// The returned frame's payload is a fresh copy, so the caller may reuse raw and
// the Codec's scratch immediately.
//
// Authentication guarantee: a frame is accepted as an authenticated kind
// (CONTROL/PROBE) only if its MAC verifies under the PSK, so tampered or
// PSK-mismatched authenticated frames are rejected. Flipping the (obfuscated)
// kind byte can re-label an authenticated frame as an unauthenticated kind
// (DATA/PARITY), which then decodes without a MAC — this is not a downgrade
// break, because DATA/PARITY are forgeable by design (the inner WireGuard layer
// authenticates the real payload). No mutation can make a frame decode as an
// authentic CONTROL/PROBE.
func (c *Codec) Decode(raw []byte) (Frame, error) {
	// Need at least the nonce plus one body byte (the kind discriminant).
	if len(raw) < nonceLen+1 {
		return nil, fmt.Errorf("%w: %d bytes, need >= %d", ErrMalformed, len(raw), nonceLen+1)
	}

	nonce := raw[:nonceLen]
	rest := raw[nonceLen:]

	// One keystream for the whole decode: init the cipher once, consume the
	// first keystream byte to recover the (obfuscated) kind, then continue the
	// SAME keystream over the remaining body. This avoids the old peekByte's
	// second ChaCha20 init.
	cipher, err := chacha20.NewUnauthenticatedCipher(c.obfKey, nonce)
	if err != nil {
		// obfKey is subkeyLen and nonce is nonceLen, so init cannot fail; a
		// failure indicates a programmer error.
		panic(fmt.Sprintf("frame: chacha20 init: %v", err))
	}
	kindByte := []byte{rest[0]}
	cipher.XORKeyStream(kindByte, kindByte)
	kind := Kind(kindByte[0])
	if !kind.valid() {
		return nil, fmt.Errorf("%w: unknown kind %d", ErrMalformed, uint8(kind))
	}

	obfBody := rest
	if kind.authenticated() {
		if len(rest) < tagLen+1 {
			return nil, fmt.Errorf("%w: authenticated frame too short", ErrMalformed)
		}
		obfBody = rest[:len(rest)-tagLen]
		gotTag := rest[len(rest)-tagLen:]
		wantTag := tag(c.authKey, nonce, obfBody)
		if !hmac.Equal(gotTag, wantTag) {
			return nil, ErrAuth
		}
	}

	// Reconstruct the plaintext body in reusable scratch. Byte 0 is the kind we
	// already recovered; the remaining bytes continue the same keystream.
	c.decScratch = append(c.decScratch[:0], obfBody...)
	body := c.decScratch
	body[0] = kindByte[0]
	if len(body) > 1 {
		cipher.XORKeyStream(body[1:], body[1:])
	}
	return decodeBody(kind, body[1:])
}

// Encode serializes f into a self-contained wire frame under the given PSK. It
// is a convenience wrapper that builds a one-shot Codec; the per-datagram
// datapath uses a long-lived Codec instead (see Codec / defect D5). It fails
// only if the PSK is unset or the system CSPRNG is unavailable.
func Encode(psk config.Key, f Frame) ([]byte, error) {
	c, err := NewCodec(psk)
	if err != nil {
		return nil, err
	}
	return c.Encode(nil, f)
}

// Decode parses a wire frame under the given PSK. It is a convenience wrapper
// that builds a one-shot Codec; hot paths reuse a long-lived Codec instead.
func Decode(psk config.Key, raw []byte) (Frame, error) {
	c, err := NewCodec(psk)
	if err != nil {
		return nil, err
	}
	return c.Decode(raw)
}

// decodeBody parses the header+payload region (the body after the kind byte).
func decodeBody(kind Kind, b []byte) (Frame, error) {
	r := reader{b: b}
	switch kind {
	case KindData:
		seq, e1 := r.u64()
		pathID, e2 := r.u8()
		group, e3 := r.u32()
		fecIndex, e4 := r.u8()
		flags, e5 := r.u8()
		if err := firstErr(e1, e2, e3, e4, e5); err != nil {
			return nil, err
		}
		return Data{OuterSeq: seq, PathID: pathID, FECGroup: group, FECIndex: fecIndex, Flags: flags, Payload: r.rest()}, nil
	case KindParity:
		group, e1 := r.u32()
		idx, e2 := r.u16()
		dataCount, e3 := r.u8()
		pathID, e4 := r.u8()
		if err := firstErr(e1, e2, e3, e4); err != nil {
			return nil, err
		}
		return Parity{FECGroup: group, ParityIndex: idx, DataCount: dataCount, PathID: pathID, Payload: r.rest()}, nil
	case KindProbe:
		pathID, e1 := r.u8()
		probeSeq, e2 := r.u64()
		ts, e3 := r.u64()
		echo, e4 := r.u8()
		sessionID, e5 := r.u64()
		challenge, e6 := r.u64()
		if err := firstErr(e1, e2, e3, e4, e5, e6); err != nil {
			return nil, err
		}
		return Probe{PathID: pathID, ProbeSeq: probeSeq, TimestampNanos: int64(ts), IsEcho: echo != 0, SessionID: sessionID, Challenge: challenge, Payload: r.rest()}, nil
	case KindControl:
		ctype, e1 := r.u8()
		seq, e2 := r.u64()
		if err := firstErr(e1, e2); err != nil {
			return nil, err
		}
		return Control{ControlType: ctype, Seq: seq, Payload: r.rest()}, nil
	default:
		// Unreachable: kind was validated by the caller.
		return nil, fmt.Errorf("%w: unknown kind %d", ErrMalformed, uint8(kind))
	}
}

// subkeys derives the obfuscation and authentication subkeys from the PSK.
func subkeys(psk config.Key) (obfKey, authKey []byte, err error) {
	if !psk.IsSet() {
		return nil, nil, errors.New("frame: PSK is not set")
	}
	secret := psk.Bytes()
	obfKey, err = hkdf.Key(sha256.New, secret[:], nil, infoObf, subkeyLen)
	if err != nil {
		return nil, nil, fmt.Errorf("frame: derive obf key: %w", err)
	}
	authKey, err = hkdf.Key(sha256.New, secret[:], nil, infoAuth, subkeyLen)
	if err != nil {
		return nil, nil, fmt.Errorf("frame: derive auth key: %w", err)
	}
	return obfKey, authKey, nil
}

// obfuscate XORs body in place with the XChaCha20 keystream derived from obfKey
// and nonce. It is its own inverse.
func obfuscate(obfKey, nonce, body []byte) {
	c, err := chacha20.NewUnauthenticatedCipher(obfKey, nonce)
	if err != nil {
		// obfKey is always subkeyLen and nonce is always nonceLen, so the cipher
		// construction cannot fail; a failure indicates a programmer error.
		panic(fmt.Sprintf("frame: chacha20 init: %v", err))
	}
	c.XORKeyStream(body, body)
}

// tag computes the truncated Encrypt-then-MAC authentication tag over
// nonce||obfBody.
func tag(authKey, nonce, obfBody []byte) []byte {
	m := hmac.New(sha256.New, authKey)
	m.Write(nonce)
	m.Write(obfBody)
	return m.Sum(nil)[:tagLen]
}

// reader is a fail-fast big-endian cursor over a byte slice.
type reader struct {
	b   []byte
	off int
}

func (r *reader) need(n int) error {
	if r.off+n > len(r.b) {
		return fmt.Errorf("%w: need %d more bytes at offset %d", ErrMalformed, n, r.off)
	}
	return nil
}

func (r *reader) u8() (uint8, error) {
	if err := r.need(1); err != nil {
		return 0, err
	}
	v := r.b[r.off]
	r.off++
	return v, nil
}

func (r *reader) u16() (uint16, error) {
	if err := r.need(2); err != nil {
		return 0, err
	}
	v := binary.BigEndian.Uint16(r.b[r.off:])
	r.off += 2
	return v, nil
}

func (r *reader) u32() (uint32, error) {
	if err := r.need(4); err != nil {
		return 0, err
	}
	v := binary.BigEndian.Uint32(r.b[r.off:])
	r.off += 4
	return v, nil
}

func (r *reader) u64() (uint64, error) {
	if err := r.need(8); err != nil {
		return 0, err
	}
	v := binary.BigEndian.Uint64(r.b[r.off:])
	r.off += 8
	return v, nil
}

// rest returns the remaining (opaque payload) bytes as a fresh copy so the
// decoded frame never aliases the caller's buffer.
func (r *reader) rest() []byte {
	n := len(r.b) - r.off
	if n == 0 {
		r.off = len(r.b)
		return nil
	}
	out := make([]byte, n)
	copy(out, r.b[r.off:])
	r.off = len(r.b)
	return out
}

func firstErr(errs ...error) error {
	for _, e := range errs {
		if e != nil {
			return e
		}
	}
	return nil
}

package config

import (
	"encoding/base64"
	"errors"
	"fmt"
	"math"
	"net/netip"
	"strconv"
	"strings"
	"time"

	awgdevice "github.com/amnezia-vpn/amneziawg-go/device"
)

// Role selects which end of the tunnel this process runs as. It is an explicit,
// required field; the role is never inferred from other configuration.
type Role string

const (
	// RoleEdge is the mobile Linux box that bonds the WAN uplinks.
	RoleEdge Role = "edge"
	// RoleConcentrator is the public-IP VPS that terminates the tunnel.
	RoleConcentrator Role = "concentrator"
)

func (r Role) valid() bool {
	return r == RoleEdge || r == RoleConcentrator
}

// keyLen is the byte length of a Curve25519 WireGuard key and of a raw
// outer-control PSK, before base64 encoding.
const keyLen = 32

// Config is the whole wanbond configuration, shared by both roles and parsed
// from a single TOML file.
type Config struct {
	Role      Role            `toml:"role"`
	Paths     []Path          `toml:"paths"`
	WireGuard WireGuard       `toml:"wireguard"`
	Amnezia   Amnezia         `toml:"amnezia"`
	PSK       Key             `toml:"psk"`
	Metrics   Metrics         `toml:"metrics"`
	Log       Log             `toml:"log"`
	Scheduler SchedulerConfig `toml:"scheduler"`
	FEC       FEC             `toml:"fec"`
}

// SchedulerPolicy selects the send-side path-selection policy the multipath Bind
// runs. It is a bounded enum: the P1 active-backup failover (default) or the T21
// weighted-aggregation policy. The policy is an explicit config choice — active-
// backup stays selectable so the P1 behaviour is never removed, only extended.
type SchedulerPolicy string

const (
	// PolicyActiveBackup is the P1 single-active-path failover scheduler: all egress
	// on the highest-priority live path, every other path idle (data-thrift by
	// construction). It is the default when [scheduler] is omitted.
	PolicyActiveBackup SchedulerPolicy = "active-backup"
	// PolicyWeighted is the T21 weighted-aggregation scheduler: under load a single
	// flow is striped across both paths in proportion to per-path RTT/loss-derived
	// weight, collapsing to the primary at low load (5G stays ~idle) with hysteresis,
	// and per-path send-pacing to bound bufferbloat.
	PolicyWeighted SchedulerPolicy = "weighted"
)

func (p SchedulerPolicy) valid() bool {
	return p == PolicyActiveBackup || p == PolicyWeighted
}

// Weighted-aggregation policy defaults (T21). They are applied when [scheduler]
// selects the weighted policy but leaves a knob at its zero value, so a minimal
// `policy = "weighted"` block is usable without hand-tuning every threshold. They
// are conservative bring-up values; the empirical per-path pace is sized from a
// measured BDP in a bandwidth-capped fixture (P0 findings §7, deferred to T35/T23),
// so the shipped default leaves pacing DISABLED and only bounds distribution.
const (
	// defaultPerPathCapacityFPS is the reference per-path capacity, in frame-selection
	// slots per second, that the aggregation load-gate compares offered load against
	// AND (when pacing is enabled) the per-path token-bucket refill rate. It is a
	// synthetic proxy for path capacity: there is no measured BDP (P0 §7), so capacity
	// is expressed in the only unit the scheduler sees — Pick() invocations per second.
	defaultPerPathCapacityFPS = 10000.0
	// defaultEngageFraction engages aggregation once offered load exceeds this
	// fraction of one path's capacity — i.e. a single path is nearly saturated.
	defaultEngageFraction = 0.9
	// defaultDisengageFraction collapses back to primary-only once offered load falls
	// below this fraction of one path's capacity. It is strictly below the engage
	// fraction: the gap is the hysteresis band that stops the 5G path from dribbling
	// on/off around a single threshold (requirement 2, data-thrift).
	defaultDisengageFraction = 0.5
	// defaultCollapseDwell is how long offered load must stay continuously below the
	// disengage fraction before aggregation collapses to primary-only — the temporal
	// half of the hysteresis, mirroring the active-backup failback dwell so a brief
	// lull does not repeatedly park then re-engage the metered path.
	defaultCollapseDwell = 2 * time.Second
	// defaultLoadTau is the time constant of the exponentially-weighted offered-load
	// rate estimator. It smooths the instantaneous Pick() arrival rate so the gate
	// reacts to sustained load, not single-frame bursts.
	defaultLoadTau = 200 * time.Millisecond
	// defaultPacingBurstFrames is the per-path token-bucket burst (in frame slots)
	// when pacing is enabled: the bucket admits up to this many frames instantaneously
	// before the refill rate binds, absorbing normal jitter without inflating a queue.
	defaultPacingBurstFrames = 64.0
	// defaultWeightRTTFloor floors the RTT in the weight formula so a path reporting a
	// near-zero RTT (cold estimator, no samples yet) cannot be handed unbounded weight.
	defaultWeightRTTFloor = 1 * time.Millisecond
	// defaultWeightLossFloor floors the loss term under the square root so a zero-loss
	// path gets a large-but-finite weight and two zero-loss paths split by inverse-RTT
	// alone rather than both diverging.
	defaultWeightLossFloor = 1e-3
)

// SchedulerConfig selects and tunes the send scheduler. When the [scheduler] block
// is omitted the policy defaults to active-backup and every weighted knob is
// ignored, so existing configs keep the P1 behaviour unchanged. The weighted knobs
// are validated (and defaulted) only when the weighted policy is selected.
type SchedulerConfig struct {
	// Policy selects the scheduler; defaults to active-backup when empty.
	Policy SchedulerPolicy `toml:"policy"`

	// PerPathCapacityFPS is the reference per-path capacity in frame-selection slots
	// per second: the denominator the aggregation load-gate compares offered load
	// against, and the per-path pacing refill rate when PacingEnabled. Must be > 0
	// under the weighted policy.
	PerPathCapacityFPS float64 `toml:"per_path_capacity_fps"`
	// EngageFraction engages aggregation when offered load exceeds
	// EngageFraction*PerPathCapacityFPS. Must be in (0,1].
	EngageFraction float64 `toml:"engage_fraction"`
	// DisengageFraction collapses aggregation to primary-only once offered load stays
	// below DisengageFraction*PerPathCapacityFPS for CollapseDwell. Must be in
	// [0,EngageFraction) — strictly below EngageFraction so the two form a hysteresis
	// band.
	DisengageFraction float64 `toml:"disengage_fraction"`
	// CollapseDwell is the sustained-low-load dwell before collapsing to primary-only
	// (hysteresis). Must be >= 0.
	CollapseDwell time.Duration `toml:"collapse_dwell"`
	// LoadTau is the offered-load rate estimator's time constant. Must be > 0.
	LoadTau time.Duration `toml:"load_tau"`

	// PacingEnabled turns per-path send-pacing on. When false the token buckets are
	// bypassed (a documented no-op — P0 §7 could not empirically size the pace in the
	// unmetered fixture), but PerPathCapacityFPS still drives the aggregation gate.
	PacingEnabled bool `toml:"pacing_enabled"`
	// PacingBurstFrames is the per-path token-bucket burst in frame slots. Must be > 0
	// when PacingEnabled.
	PacingBurstFrames float64 `toml:"pacing_burst_frames"`

	// WeightRTTFloor floors RTT in the weight formula (must be > 0 under weighted).
	WeightRTTFloor time.Duration `toml:"weight_rtt_floor"`
	// WeightLossFloor floors the loss term under the square root (must be > 0 under
	// weighted).
	WeightLossFloor float64 `toml:"weight_loss_floor"`
}

// BDPSizing is a per-path pacing sizing derived from a MEASURED path, in the
// frame-selection-slot units the weighted scheduler pace uses (defect D22). It is the
// empirical alternative to the synthetic frame-count defaults: CapacityFPS replaces
// PerPathCapacityFPS and BurstFrames replaces PacingBurstFrames.
type BDPSizing struct {
	// CapacityFPS is the sustained per-path frame rate the measured bottleneck bandwidth
	// supports (the token-bucket refill rate and aggregation-gate denominator).
	CapacityFPS float64
	// BurstFrames is the bandwidth-delay product expressed in frames (bandwidth x RTT,
	// i.e. one RTT of in-flight frames): the token-bucket burst that absorbs one RTT of
	// jitter without building a standing queue.
	BurstFrames float64
}

// defaultAvgWireFrameBytes is the conservative average on-wire outer-frame size used
// when deriving the per-path pace from an operator-declared bandwidth at config load
// (T53): a full IPv4 path MTU, since a full-MTU DATA datagram occupies about one path
// MTU on the wire. It mirrors bind.DefaultPathMTU (1500) rather than importing it —
// internal/bind imports internal/config, so config cannot import bind without a cycle
// (the same mirror-with-cross-reference pattern as maxFECDeadline above). Sizing
// capacity with the full-MTU frame is the conservative floor: smaller average frames
// would yield a HIGHER frame rate, so this never over-paces a path.
const defaultAvgWireFrameBytes = 1500.0

// SizePacingFromBDP derives the weighted scheduler's per-path pacing parameters from a
// measured path instead of the synthetic frame-count default (defect D22). The shipped
// defaultPerPathCapacityFPS (10000, ~115 Mbit/s at full MTU) sits far above a realistic
// slow uplink, so the aggregation gate may never engage and — with pacing enabled — the
// pace never binds; deriving capacity from the measured bottleneck bandwidth fixes both.
//
// capacity_fps = bandwidth / (8 * avg wire frame bytes) — frames/s the link sustains.
// burst_frames = capacity_fps * RTT — one RTT of in-flight frames (equivalently
// BDP_bytes / avg wire frame bytes, since the bandwidth-delay product BDP = bandwidth * RTT).
//
// bandwidthBitsPerSec is the measured bottleneck bandwidth (bits/s), rtt the measured
// path RTT, and avgWireFrameBytes the average on-wire outer-frame size (a full-MTU
// datagram plus frame.DataOverhead is the conservative choice). It fails fast on a
// non-positive input rather than emitting a nonsensical (zero/negative/Inf) sizing.
func SizePacingFromBDP(bandwidthBitsPerSec float64, rtt time.Duration, avgWireFrameBytes float64) (BDPSizing, error) {
	if bandwidthBitsPerSec <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing bandwidth must be > 0 bit/s, got %g", bandwidthBitsPerSec)
	}
	if rtt <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing RTT must be > 0, got %s", rtt)
	}
	if avgWireFrameBytes <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing average wire frame size must be > 0 bytes, got %g", avgWireFrameBytes)
	}
	const bitsPerByte = 8.0
	capacityFPS := bandwidthBitsPerSec / (bitsPerByte * avgWireFrameBytes)
	burstFrames := capacityFPS * rtt.Seconds()
	return BDPSizing{CapacityFPS: capacityFPS, BurstFrames: burstFrames}, nil
}

// bandwidthUnit is a recognised link_bandwidth suffix and its bit/s multiplier.
type bandwidthUnit struct {
	suffix string
	mult   float64
}

// bandwidthUnits are the accepted operator-facing bandwidth suffixes, longest-first so
// "gbit" is matched before "bit". SI decimal multipliers (k/M/G = 1e3/1e6/1e9) over a
// bit/s base; "bps" is accepted as an alias of "bit" (and "kbps"/"mbps"/"gbps" likewise).
var bandwidthUnits = []bandwidthUnit{
	{"gbit", 1e9}, {"gbps", 1e9},
	{"mbit", 1e6}, {"mbps", 1e6},
	{"kbit", 1e3}, {"kbps", 1e3},
	{"bit", 1}, {"bps", 1},
}

// parseBandwidth parses an operator-declared link bandwidth such as "50Mbit", "1Gbit",
// or "500kbit" into bits per second. It requires an explicit bit/s unit suffix so a
// bare unitless number cannot be silently misread, and fails fast on an empty or
// otherwise unparseable value — a mistyped bandwidth is rejected at config load.
func parseBandwidth(s string) (float64, error) {
	lower := strings.ToLower(strings.TrimSpace(s))
	if lower == "" {
		return 0, errors.New("empty bandwidth")
	}
	for _, u := range bandwidthUnits {
		if !strings.HasSuffix(lower, u.suffix) {
			continue
		}
		num := strings.TrimSpace(lower[:len(lower)-len(u.suffix)])
		val, err := strconv.ParseFloat(num, 64)
		if err != nil {
			return 0, fmt.Errorf("invalid number %q", num)
		}
		return val * u.mult, nil
	}
	return 0, fmt.Errorf("missing bit/s unit suffix (want e.g. %q)", "50Mbit")
}

// FEC group-close deadline default (T24). Applied only when [fec] is enabled but
// leaves the deadline at its zero value, so a minimal `enabled = true` block emits
// parity for a partially-filled group promptly under low load rather than stranding
// it until the size threshold fills.
const defaultFECDeadline = 5 * time.Millisecond

// defaultAdaptiveSafetyFactor mirrors adaptivefec.DefaultSafetyFactor (1.5), the
// simulation-proven controller default, restated here (with this cross-reference rather
// than an import) so a minimal `adaptive = true` block gets the proven tuning without
// coupling config to the controller package. NOTE: 1.5 sizes M for the mean loss with
// modest variance headroom; a tight residual SLA under a specific loss/geometry may need a
// higher factor (e.g. at 5% loss with K=10 the 1.5 default sizes M=1, ~1% residual — raise
// this to lift M and drive the residual down).
const defaultAdaptiveSafetyFactor = 1.5

// maxFECDeadline bounds the FEC group-close deadline at load time (T24, defect #4). It
// MUST stay at or below the multipath Bind's authoritative bound (bind.maxFECDeadline =
// resequencerTimeout/2 = 125ms): a group flushed by the deadline emits its parity
// `deadline` after opening, and the reconstructed frames must reach the receive
// resequencer BEFORE it skips the gap (its 250ms per-gap timeout) — otherwise recovery
// is structurally too late (the gap is skipped, the recovered frame dropped as past the
// release point) while /metrics would still count it reconstructed. Rejecting an
// over-large deadline at load makes that coupling fail-fast and explicit rather than
// silently defeating FEC. Kept in lockstep with bind.maxFECDeadline (the packages
// cannot import each other, so the value is mirrored with this cross-reference).
const maxFECDeadline = 125 * time.Millisecond

// maxFECShards mirrors the Reed-Solomon field limit enforced in internal/fec: a
// coding group carries at most 256 shards (data + parity) total over GF(2^8). It
// is restated here so config load fails fast on an over-large ratio at the right
// locus, with the same bound the codec enforces internally.
const maxFECShards = 256

// FEC configures the fixed-ratio Reed-Solomon forward-error-correction plane (T24).
// It is DISABLED by default (like pacing), so an existing config with no [fec] block
// runs the datapath exactly as before — FEC transparent, no parity on the wire. When
// enabled, each group of DataShards (K) inner datagrams is protected by ParityShards
// (M) parity frames, letting the receiver reconstruct up to M lost data frames per
// group at a fixed M/K parity overhead.
type FEC struct {
	// Enabled turns the FEC plane on. When false every other field is ignored and the
	// datapath carries no parity.
	Enabled bool `toml:"enabled"`
	// DataShards is K: the number of inner datagrams grouped before parity is emitted.
	// Must be >= 1 when enabled.
	DataShards int `toml:"data_shards"`
	// ParityShards is M: the parity frames emitted per group and the maximum number of
	// per-group data losses the receiver can recover. Must be >= 1 when enabled. In
	// adaptive mode it is the CEILING (and the receiver's decoder cardinality) — the
	// controller drives the per-group parity in [0,ParityShards] to track measured loss.
	ParityShards int `toml:"parity_shards"`
	// Deadline bounds grouping latency: a partially-filled group is flushed (parity
	// emitted over its current data frames) once this much time has elapsed since its
	// first frame. Defaults to defaultFECDeadline when enabled and left zero; must be
	// > 0 after defaulting.
	Deadline time.Duration `toml:"deadline"`
	// Adaptive opts the send-side FEC into the closed-loop controller (T27/T29): the
	// per-group parity count tracks the measured per-path loss instead of standing at
	// the fixed ParityShards ratio, so a clean path spends near-zero overhead while a
	// lossy one is masked. It is OFF by default, so an existing [fec] block keeps the
	// fixed-ratio behaviour (T24) byte-for-byte. When true, ParityShards is reinterpreted
	// as the controller's parity ceiling (see above); the receiver is unchanged because a
	// group coded with fewer parity shards decodes against the ParityShards-ceiling codec
	// unchanged (klauspost's parity is prefix-consistent).
	Adaptive bool `toml:"adaptive"`
	// SafetyFactor is the adaptive controller's headroom multiplier over the measured mean
	// loss the per-group parity is sized to mask (adaptivefec.Config.SafetyFactor). It is
	// the residual-loss LEVER: the controller sizes M so M/(K+M) >= SafetyFactor*loss, so a
	// higher factor spends more parity to keep the post-recovery residual under a tighter
	// bound against binomial per-group variance. Applies only in adaptive mode; defaults to
	// defaultAdaptiveSafetyFactor (the simulation-proven controller default) when left zero
	// AND target_residual is unset, and must be >= 1. Ignored (and must stay zero) in fixed
	// mode, and mutually exclusive with target_residual (set one, not both).
	SafetyFactor float64 `toml:"safety_factor"`
	// TargetResidual is the adaptive controller's target POST-RECOVERY residual-loss SLA
	// (a fraction in (0,1)) and the PRIMARY adaptive sizing surface (D26/T46): the
	// controller derives the per-group parity M by inverting the binomial residual model
	// E[max(0,D-M)]/K (D ~ Bin(K, smoothed loss)) to the smallest M meeting this target,
	// capped at the parity ceiling (parity_shards). It SUPERSEDES safety_factor — set
	// EITHER a residual SLA (target_residual, recommended: it maps an operator's loss
	// budget directly to redundancy) OR the bare headroom multiplier (safety_factor), never
	// both. Applies only in adaptive mode; unset (0) selects the safety_factor path. Must
	// be in (0,1) when set. Ignored (and must stay zero) in fixed mode.
	TargetResidual float64 `toml:"target_residual"`
}

// applyDefaults fills the group-close deadline when FEC is enabled and the deadline
// was left at zero. It is a no-op for a disabled block, so a config that never turns
// FEC on keeps an empty [fec] surface.
func (f *FEC) applyDefaults() {
	if !f.Enabled {
		return
	}
	if f.Deadline == 0 {
		f.Deadline = defaultFECDeadline
	}
	// The SafetyFactor default is applied only in the legacy sizing mode: when
	// target_residual is set it is the primary surface and safety_factor stays inert
	// (0), so defaulting it would spuriously trip the mutual-exclusion check.
	if f.Adaptive && f.TargetResidual == 0 && f.SafetyFactor == 0 {
		f.SafetyFactor = defaultAdaptiveSafetyFactor
	}
}

// validate enforces the FEC ratio invariants, failing fast so a mis-tuned parity
// ratio is rejected at load rather than panicking the codec at runtime. A disabled
// block needs no tuning. The bounds mirror internal/fec's own Config.validate.
func (f FEC) validate() error {
	if !f.Enabled {
		if f.Adaptive {
			return errors.New("fec.adaptive = true requires fec.enabled = true (adaptive FEC is meaningless with the plane off)")
		}
		return nil
	}
	if f.DataShards < 1 {
		return fmt.Errorf("fec.data_shards must be >= 1 when FEC is enabled, got %d", f.DataShards)
	}
	if f.ParityShards < 1 {
		return fmt.Errorf("fec.parity_shards must be >= 1 when FEC is enabled, got %d", f.ParityShards)
	}
	if f.DataShards+f.ParityShards > maxFECShards {
		return fmt.Errorf("fec.data_shards + fec.parity_shards must be <= %d (Reed-Solomon field limit), got %d", maxFECShards, f.DataShards+f.ParityShards)
	}
	if f.Deadline <= 0 {
		return fmt.Errorf("fec.deadline must be > 0 when FEC is enabled, got %s", f.Deadline)
	}
	if f.Deadline > maxFECDeadline {
		return fmt.Errorf("fec.deadline must be <= %s (safely below the receive resequencer's per-gap timeout so deadline-flushed recovery lands before the gap is skipped), got %s", maxFECDeadline, f.Deadline)
	}
	if f.Adaptive {
		if f.TargetResidual != 0 {
			// Residual-SLA sizing mode (primary): target_residual governs and safety_factor
			// stays inert, so setting both is an ambiguous mis-config — reject it. NaN is
			// caught explicitly because every ordered comparison against it is false.
			if math.IsNaN(f.TargetResidual) || f.TargetResidual <= 0 || f.TargetResidual >= 1 {
				return fmt.Errorf("fec.target_residual must be a finite value in (0,1), got %g", f.TargetResidual)
			}
			if f.SafetyFactor != 0 {
				return fmt.Errorf("fec.safety_factor and fec.target_residual are mutually exclusive; target_residual is the primary residual-SLA surface — set one, not both")
			}
		} else if f.SafetyFactor < 1 {
			// SafetyFactor is defaulted to defaultAdaptiveSafetyFactor when zero, so a value
			// below 1 here is an explicit mis-set: the controller requires >= 1 (masking less
			// than the mean loss is nonsensical), matching adaptivefec.Config.Validate.
			return fmt.Errorf("fec.safety_factor must be >= 1 in adaptive mode, got %g", f.SafetyFactor)
		}
	} else if f.SafetyFactor != 0 || f.TargetResidual != 0 {
		return fmt.Errorf("fec.safety_factor / fec.target_residual are only meaningful in adaptive mode (set fec.adaptive = true), got safety_factor=%g target_residual=%g", f.SafetyFactor, f.TargetResidual)
	}
	return nil
}

// Path is one physical WAN uplink. The edge binds each path's UDP socket to
// SourceAddr so the upstream router pins it to the intended WAN; the
// concentrator learns the real per-path endpoints from authenticated traffic.
type Path struct {
	// Name is a stable human-readable identifier for the path (e.g. "starlink").
	Name string `toml:"name"`
	// SourceAddr is the local source IP the path's socket binds to.
	SourceAddr netip.Addr `toml:"-"`
	// SourceAddrRaw is the TOML string form of SourceAddr; parsed in normalize.
	SourceAddrRaw string `toml:"source_addr"`
	// DestAddr is the OPTIONAL per-path concentrator endpoint ("ip:port") the
	// edge sends this path's datagrams to. It is unset on the concentrator (which
	// learns edge endpoints from traffic) and optional on the edge: when a single
	// public concentrator IP fronts all uplinks (the common source-routed case)
	// the peer's wireguard endpoint is reused for every path; when the paths reach
	// the concentrator on distinct addresses, set dest_addr per path.
	DestAddr netip.AddrPort `toml:"-"`
	// DestAddrRaw is the TOML string form of DestAddr; parsed in normalize.
	DestAddrRaw string `toml:"dest_addr"`
	// LinkBandwidthBitsPerSec is the OPERATOR-DECLARED bottleneck bandwidth of this
	// uplink in bits/s, parsed from LinkBandwidthRaw in normalize. It is used ONLY to
	// size the weighted scheduler's per-path pace from the bandwidth-delay product
	// (SizePacingFromBDP) when the weighted policy runs with pacing ENABLED (T53, Q20);
	// it is OPERATOR-DECLARED, not runtime-measured — wanbond never auto-tunes it live.
	// Zero means "not declared" (the synthetic default pace is kept).
	LinkBandwidthBitsPerSec float64 `toml:"-"`
	// LinkBandwidthRaw is the TOML string form of the declared bandwidth, e.g.
	// "50Mbit" / "1Gbit" / "500kbit" (SI bit/s units; the "bit" suffix may be written
	// "bps"). Parsed in normalize; a non-positive or unparseable value fails fast.
	LinkBandwidthRaw string `toml:"link_bandwidth"`
	// LinkRTT is the OPERATOR-DECLARED baseline RTT of this uplink, parsed from
	// LinkRTTRaw in normalize. It is the delay term of the bandwidth-delay-product pace
	// burst (one RTT of in-flight frames); required (> 0) when LinkBandwidth is set and
	// pacing is enabled under the weighted policy, ignored otherwise.
	LinkRTT time.Duration `toml:"-"`
	// LinkRTTRaw is the TOML Go-duration string form of LinkRTT, e.g. "45ms". Parsed in
	// normalize; an unparseable or non-positive value fails fast.
	LinkRTTRaw string `toml:"link_rtt"`
}

// WireGuard holds the inner tunnel's key material.
type WireGuard struct {
	PrivateKey Key    `toml:"private_key"`
	Peers      []Peer `toml:"peers"`
	// ListenPort is the UDP port the concentrator listens on; 0 on the edge.
	ListenPort uint16 `toml:"listen_port"`
}

// Peer is one WireGuard peer.
type Peer struct {
	PublicKey Key `toml:"public_key"`
	// Endpoint is the peer's SINGLE tunnel address (edge -> concentrator); the
	// legacy single-endpoint config form, mutually exclusive with EndpointsRaw.
	// Empty on the concentrator, which roams the edge's endpoint dynamically.
	// A bare `endpoint = "..."` is normalized in resolveEndpoints to a one-
	// element Endpoints list, so it stays behavior-identical to the pre-T54
	// config surface.
	Endpoint string `toml:"endpoint"`
	// EndpointsRaw is the ORDERED list of concentrator (peer) endpoint address:port
	// strings for the edge-side hub-failover config surface (Q18): index 0 is the
	// active/primary concentrator, the rest are ordered standbys. Edge-only; a
	// concentrator declaring it is a config error (validate). Mutually exclusive
	// with the legacy Endpoint field.
	EndpointsRaw []string `toml:"endpoints"`
	// Endpoints is EndpointsRaw (or the single legacy Endpoint, as a one-element
	// list) parsed to netip.AddrPort and de-duplicated; populated by
	// resolveEndpoints in normalize(). This is the shape T57's hub-failover
	// switch consumes: Endpoints[0] is the active concentrator, Endpoints[1:]
	// are the ordered standbys to fail over to in order when all paths to the
	// active one are down.
	Endpoints []netip.AddrPort `toml:"-"`
	// AllowedIPs are the CIDR ranges routed to this peer.
	AllowedIPs []string `toml:"allowed_ips"`
}

// resolveEndpoints canonicalizes the peer's endpoint config into the ordered
// Endpoints list (Q18): the legacy single Endpoint field and the new ordered
// EndpointsRaw list are mutually exclusive input forms, but a bare `endpoint =
// "..."` is normalized here to a ONE-ELEMENT Endpoints list — so it stays
// behavior-identical to the pre-T54 single-defaultRemote config surface. Each
// entry must parse as netip.AddrPort ("host:port"), the same format
// bind.Multipath.ParseEndpoint requires of the UAPI endpoint string at
// runtime, and duplicates within the list are rejected.
func (p *Peer) resolveEndpoints() error {
	if p.Endpoint != "" && len(p.EndpointsRaw) > 0 {
		return errors.New("endpoint and endpoints are mutually exclusive; endpoint is the single-entry legacy form of endpoints")
	}
	raw := p.EndpointsRaw
	if p.Endpoint != "" {
		raw = []string{p.Endpoint}
	}
	seen := make(map[netip.AddrPort]struct{}, len(raw))
	endpoints := make([]netip.AddrPort, 0, len(raw))
	for _, s := range raw {
		ap, err := netip.ParseAddrPort(s)
		if err != nil {
			return fmt.Errorf("invalid endpoint %q: %w", s, err)
		}
		if _, dup := seen[ap]; dup {
			return fmt.Errorf("duplicate endpoint %q", s)
		}
		seen[ap] = struct{}{}
		endpoints = append(endpoints, ap)
	}
	p.Endpoints = endpoints
	return nil
}

// Amnezia holds the amneziawg-go obfuscation parameters. They must match on both
// ends for the handshake to succeed; they are defense-in-depth only.
//
// The block is "all-or-nothing": either every junk/size knob is left zero (plain
// WireGuard) or the whole obfuscation set (jc, jmin, jmax, s1, s2) is specified.
// A PARTIAL block silently produces an obfuscation profile the two ends cannot
// agree on, so validate rejects it at load (defect D1). The four magic headers
// (h1-h4) default to the standard message-type values 1..4 when omitted.
type Amnezia struct {
	Jc   int    `toml:"jc"`
	Jmin int    `toml:"jmin"`
	Jmax int    `toml:"jmax"`
	S1   int    `toml:"s1"`
	S2   int    `toml:"s2"`
	H1   uint32 `toml:"h1"`
	H2   uint32 `toml:"h2"`
	H3   uint32 `toml:"h3"`
	H4   uint32 `toml:"h4"`
}

// defaultMagicHeaders are the standard WireGuard message-type headers: initiation,
// response, cookie-reply, and transport. amneziawg-go treats any magic header <= 4
// as "use the standard type", so 1..4 is the canonical "headers not obfuscated"
// profile. wanbond emits them explicitly (rather than 0) so a configured amnezia
// block always carries a complete, self-consistent set of magic headers.
var defaultMagicHeaders = [4]uint32{1, 2, 3, 4}

// Configured reports whether the amnezia block carries any obfuscation parameter.
// An all-zero block leaves the engine in plain WireGuard mode.
func (a Amnezia) Configured() bool {
	return a.Jc != 0 || a.Jmin != 0 || a.Jmax != 0 || a.S1 != 0 || a.S2 != 0 ||
		a.H1 != 0 || a.H2 != 0 || a.H3 != 0 || a.H4 != 0
}

// applyDefaults fills in the standard magic headers (1..4) when the block is
// configured but no header was given, so the UAPI renderer emits an explicit,
// complete header set instead of h1=0..h4=0. It is a no-op for an unconfigured
// block and for one that already sets any header (a partial header set is left
// intact so validate can reject it).
func (a *Amnezia) applyDefaults() {
	if !a.Configured() {
		return
	}
	if a.H1 == 0 && a.H2 == 0 && a.H3 == 0 && a.H4 == 0 {
		a.H1, a.H2, a.H3, a.H4 = defaultMagicHeaders[0], defaultMagicHeaders[1], defaultMagicHeaders[2], defaultMagicHeaders[3]
	}
}

// Metrics configures the localhost Prometheus endpoint.
type Metrics struct {
	// Listen is the address the /metrics endpoint binds to; must be loopback.
	Listen string `toml:"listen"`
}

// Log configures structured logging.
type Log struct {
	Level string `toml:"level"`
}

// Key is a 32-byte Curve25519 key or PSK, carried in TOML as standard base64.
type Key struct {
	bytes [keyLen]byte
	set   bool
}

// UnmarshalText decodes a base64 key. An empty string leaves the Key unset so
// optional keys can be distinguished from present-but-invalid ones.
func (k *Key) UnmarshalText(text []byte) error {
	if len(text) == 0 {
		return nil
	}
	raw, err := base64.StdEncoding.DecodeString(string(text))
	if err != nil {
		return fmt.Errorf("key is not valid base64: %w", err)
	}
	if len(raw) != keyLen {
		return fmt.Errorf("key must decode to %d bytes, got %d", keyLen, len(raw))
	}
	copy(k.bytes[:], raw)
	k.set = true
	return nil
}

// IsSet reports whether the key was present and valid.
func (k Key) IsSet() bool { return k.set }

// Bytes returns the raw key material.
func (k Key) Bytes() [keyLen]byte { return k.bytes }

// normalize parses the string-typed fields (addresses) into their typed forms.
func (c *Config) normalize() error {
	for i := range c.Paths {
		p := &c.Paths[i]
		if p.SourceAddrRaw != "" {
			addr, err := netip.ParseAddr(p.SourceAddrRaw)
			if err != nil {
				return fmt.Errorf("path %q: invalid source_addr %q: %w", p.Name, p.SourceAddrRaw, err)
			}
			p.SourceAddr = addr
		}
		if p.DestAddrRaw != "" {
			dst, err := netip.ParseAddrPort(p.DestAddrRaw)
			if err != nil {
				return fmt.Errorf("path %q: invalid dest_addr %q: %w", p.Name, p.DestAddrRaw, err)
			}
			p.DestAddr = dst
		}
		if p.LinkBandwidthRaw != "" {
			bw, err := parseBandwidth(p.LinkBandwidthRaw)
			if err != nil {
				return fmt.Errorf("path %q: invalid link_bandwidth %q: %w", p.Name, p.LinkBandwidthRaw, err)
			}
			if bw <= 0 {
				return fmt.Errorf("path %q: link_bandwidth must be > 0, got %q", p.Name, p.LinkBandwidthRaw)
			}
			p.LinkBandwidthBitsPerSec = bw
		}
		if p.LinkRTTRaw != "" {
			rtt, err := time.ParseDuration(p.LinkRTTRaw)
			if err != nil {
				return fmt.Errorf("path %q: invalid link_rtt %q: %w", p.Name, p.LinkRTTRaw, err)
			}
			if rtt <= 0 {
				return fmt.Errorf("path %q: link_rtt must be > 0, got %q", p.Name, p.LinkRTTRaw)
			}
			p.LinkRTT = rtt
		}
	}
	for i := range c.WireGuard.Peers {
		if err := c.WireGuard.Peers[i].resolveEndpoints(); err != nil {
			return fmt.Errorf("wireguard peer %d: %w", i, err)
		}
	}
	c.Amnezia.applyDefaults()
	// Derive the weighted pace from any operator-declared per-link bandwidth BEFORE
	// applyDefaults, so it can (a) see the raw zero PerPathCapacityFPS to distinguish an
	// explicit knob from the default and (b) set the derived capacity/burst that
	// applyDefaults then leaves intact (it only fills a knob left at zero). Under a
	// disabled or non-weighted pacing it is a no-op, so the synthetic default is kept.
	if err := c.deriveWeightedPacingFromBDP(); err != nil {
		return err
	}
	c.Scheduler.applyDefaults()
	c.FEC.applyDefaults()
	return nil
}

// deriveWeightedPacingFromBDP sizes the weighted scheduler's per-path pace from the
// operator-declared per-link bandwidth (T53, Q20) via SizePacingFromBDP instead of the
// synthetic defaultPerPathCapacityFPS. It runs only under the weighted policy with
// pacing ENABLED and at least one declared link_bandwidth; otherwise a declared
// bandwidth is inert (pacing ships DISABLED by default), so an unrelated config is
// untouched. The value is OPERATOR-DECLARED and fixed at load — NOT runtime auto-tuning
// (Q20 rejected a live control loop for the pilot).
//
// The scheduler carries a SINGLE reference per-path capacity applied to every path's
// token bucket, so a heterogeneous link set is sized to the BOTTLENECK: the slowest
// declared link governs the shared pace, because pacing any path faster than the
// slowest link's capacity would let that link build the very standing queue pacing
// exists to prevent. All paths must therefore declare a bandwidth (all-or-nothing) so
// the bottleneck is well-defined across the whole path set.
func (c *Config) deriveWeightedPacingFromBDP() error {
	s := &c.Scheduler
	if s.Policy != PolicyWeighted || !s.PacingEnabled {
		return nil
	}
	declared := 0
	for i := range c.Paths {
		if c.Paths[i].LinkBandwidthBitsPerSec > 0 {
			declared++
		}
	}
	if declared == 0 {
		return nil // no declared bandwidth: the synthetic default pace is preserved.
	}
	if declared != len(c.Paths) {
		return fmt.Errorf("scheduler pacing: link_bandwidth must be declared on ALL paths or none (got %d of %d) — the shared per-path pace is sized to the slowest declared link, which is undefined with a partial declaration", declared, len(c.Paths))
	}
	if s.PerPathCapacityFPS != 0 || s.PacingBurstFrames != 0 {
		return errors.New("scheduler.per_path_capacity_fps / pacing_burst_frames and per-path link_bandwidth are mutually exclusive: declare the link bandwidth (BDP-derived pace) OR set the raw frame-slot knobs, not both")
	}
	var bottleneck BDPSizing
	for i := range c.Paths {
		p := &c.Paths[i]
		if p.LinkRTT <= 0 {
			return fmt.Errorf("path %q: link_rtt is required (> 0) when link_bandwidth is set under weighted pacing — it is the delay term of the bandwidth-delay-product burst", p.Name)
		}
		sz, err := SizePacingFromBDP(p.LinkBandwidthBitsPerSec, p.LinkRTT, defaultAvgWireFrameBytes)
		if err != nil {
			return fmt.Errorf("path %q: %w", p.Name, err)
		}
		if i == 0 || sz.CapacityFPS < bottleneck.CapacityFPS {
			bottleneck = sz
		}
	}
	s.PerPathCapacityFPS = bottleneck.CapacityFPS
	s.PacingBurstFrames = bottleneck.BurstFrames
	return nil
}

// applyDefaults selects active-backup when no policy is given and, only under the
// weighted policy, fills any weighted knob left at its zero value with its default.
// It is a no-op for the active-backup policy: those weighted knobs are inert there,
// so leaving them zero keeps the config surface for a P1 deployment empty.
func (s *SchedulerConfig) applyDefaults() {
	if s.Policy == "" {
		s.Policy = PolicyActiveBackup
	}
	if s.Policy != PolicyWeighted {
		return
	}
	if s.PerPathCapacityFPS == 0 {
		s.PerPathCapacityFPS = defaultPerPathCapacityFPS
	}
	if s.EngageFraction == 0 {
		s.EngageFraction = defaultEngageFraction
	}
	if s.DisengageFraction == 0 {
		s.DisengageFraction = defaultDisengageFraction
	}
	if s.CollapseDwell == 0 {
		s.CollapseDwell = defaultCollapseDwell
	}
	if s.LoadTau == 0 {
		s.LoadTau = defaultLoadTau
	}
	if s.PacingBurstFrames == 0 {
		s.PacingBurstFrames = defaultPacingBurstFrames
	}
	if s.WeightRTTFloor == 0 {
		s.WeightRTTFloor = defaultWeightRTTFloor
	}
	if s.WeightLossFloor == 0 {
		s.WeightLossFloor = defaultWeightLossFloor
	}
}

// validate enforces the scheduler policy invariants. active-backup needs no tuning.
// The weighted policy fails fast on any out-of-range knob so a mis-tuned
// aggregation policy is rejected at load rather than misbehaving at runtime (the
// hysteresis band, in particular, is only a band when disengage < engage).
func (s SchedulerConfig) validate() error {
	if !s.Policy.valid() {
		return fmt.Errorf("scheduler.policy must be %q or %q, got %q", PolicyActiveBackup, PolicyWeighted, s.Policy)
	}
	if s.Policy != PolicyWeighted {
		return nil
	}
	if s.PerPathCapacityFPS <= 0 {
		return fmt.Errorf("scheduler.per_path_capacity_fps must be > 0 under the weighted policy, got %g", s.PerPathCapacityFPS)
	}
	if s.EngageFraction <= 0 || s.EngageFraction > 1 {
		return fmt.Errorf("scheduler.engage_fraction must be in (0,1], got %g", s.EngageFraction)
	}
	if s.DisengageFraction < 0 || s.DisengageFraction >= s.EngageFraction {
		return fmt.Errorf("scheduler.disengage_fraction must be in [0,engage_fraction=%g) to form a hysteresis band, got %g", s.EngageFraction, s.DisengageFraction)
	}
	if s.CollapseDwell < 0 {
		return fmt.Errorf("scheduler.collapse_dwell must be >= 0, got %s", s.CollapseDwell)
	}
	if s.LoadTau <= 0 {
		return fmt.Errorf("scheduler.load_tau must be > 0, got %s", s.LoadTau)
	}
	if s.PacingEnabled && s.PacingBurstFrames <= 0 {
		return fmt.Errorf("scheduler.pacing_burst_frames must be > 0 when pacing is enabled, got %g", s.PacingBurstFrames)
	}
	if s.WeightRTTFloor <= 0 {
		return fmt.Errorf("scheduler.weight_rtt_floor must be > 0 under the weighted policy, got %s", s.WeightRTTFloor)
	}
	if s.WeightLossFloor <= 0 {
		return fmt.Errorf("scheduler.weight_loss_floor must be > 0 under the weighted policy, got %g", s.WeightLossFloor)
	}
	return nil
}

// validate enforces the required-field invariants, failing on the first problem.
func (c *Config) validate() error {
	if !c.Role.valid() {
		return fmt.Errorf("role must be %q or %q, got %q", RoleEdge, RoleConcentrator, c.Role)
	}
	if len(c.Paths) == 0 {
		return errors.New("at least one path is required")
	}
	seen := make(map[string]struct{}, len(c.Paths))
	// seenSrc maps an already-claimed source_addr to the path that claimed it, so a
	// second path reusing it can be rejected at LOAD naming both conflicting paths.
	// The multipath bind Opens each path on (source_addr, listen_port), so two paths
	// sharing a source_addr collide EADDRINUSE at the second ListenUDP (and on every
	// re-Open after Down/Up, since the engine passes the fixed port back) — a
	// misconfiguration that must fail fast at load, not at bring-up (defect D10).
	seenSrc := make(map[netip.Addr]string, len(c.Paths))
	for i, p := range c.Paths {
		if p.Name == "" {
			return fmt.Errorf("path %d: name is required", i)
		}
		if _, dup := seen[p.Name]; dup {
			return fmt.Errorf("duplicate path name %q", p.Name)
		}
		seen[p.Name] = struct{}{}
		if !p.SourceAddr.IsValid() {
			return fmt.Errorf("path %q: source_addr is required", p.Name)
		}
		// Compare the UNMAPPED form: "192.0.2.10" (Is4) and "::ffff:192.0.2.10"
		// (Is4In6) are distinct under netip == yet bind the identical v4 socket, so
		// the two spellings must collide in the guard exactly as they do at bind.
		src := p.SourceAddr.Unmap()
		if prev, dup := seenSrc[src]; dup {
			return fmt.Errorf("paths %q and %q share source_addr %s; each path must bind a distinct source address (a shared source collides EADDRINUSE at the second bind)", prev, p.Name, p.SourceAddr)
		}
		seenSrc[src] = p.Name
	}
	if !c.WireGuard.PrivateKey.IsSet() {
		return errors.New("wireguard.private_key is required")
	}
	if len(c.WireGuard.Peers) == 0 {
		return errors.New("at least one wireguard peer is required")
	}
	for i, peer := range c.WireGuard.Peers {
		if !peer.PublicKey.IsSet() {
			return fmt.Errorf("wireguard peer %d: public_key is required", i)
		}
		if c.Role == RoleEdge && len(peer.Endpoints) == 0 {
			return fmt.Errorf("wireguard peer %d: endpoint is required for the edge role", i)
		}
		// The concentrator learns the edge's endpoint dynamically (roaming across
		// NAT rebinds); an ordered failover endpoint list is meaningless for it, so
		// reject rather than silently ignore a mis-targeted config (Q18 is edge-side
		// only).
		if c.Role == RoleConcentrator && len(peer.Endpoints) != 0 {
			return fmt.Errorf("wireguard peer %d: endpoint/endpoints is not meaningful for the concentrator role (it learns the edge's endpoint dynamically)", i)
		}
	}
	if c.Role == RoleConcentrator && c.WireGuard.ListenPort == 0 {
		return errors.New("wireguard.listen_port is required for the concentrator role")
	}
	if !c.PSK.IsSet() {
		return errors.New("psk is required (authenticates outer control/probe frames)")
	}
	if err := c.Amnezia.validate(); err != nil {
		return err
	}
	if err := c.Scheduler.validate(); err != nil {
		return err
	}
	if err := c.FEC.validate(); err != nil {
		return err
	}
	return nil
}

// validate enforces the amnezia obfuscation invariants (defect D1). An
// unconfigured block is valid (plain WireGuard). A configured block must specify
// the WHOLE junk/size set and carry a consistent magic-header set, so a partial
// or inconsistent obfuscation profile FAILS FAST at load rather than producing a
// silently mismatched tunnel that never handshakes.
//
// This runs after applyDefaults, so an omitted magic-header set has already been
// filled with the standard 1..4 values; the header check below therefore only
// fires for a genuinely partial header set (some given, some left zero).
func (a Amnezia) validate() error {
	if !a.Configured() {
		return nil
	}
	// All-or-nothing: enabling amnezia at all requires the full junk/size set, so
	// both ends are forced to specify the same complete profile. A partial block
	// (e.g. jc/jmin/jmax set but s1/s2 omitted) would leave the ends deriving
	// different profiles and the handshake would fail closed with no diagnostic.
	if a.Jc <= 0 || a.Jmin <= 0 || a.Jmax <= 0 || a.S1 <= 0 || a.S2 <= 0 {
		return fmt.Errorf("amnezia: incomplete obfuscation set — when configured, jc, jmin, jmax, s1 and s2 must all be > 0 (got jc=%d jmin=%d jmax=%d s1=%d s2=%d)",
			a.Jc, a.Jmin, a.Jmax, a.S1, a.S2)
	}
	if a.Jmin > a.Jmax {
		return fmt.Errorf("amnezia: require jmin <= jmax, got jmin=%d jmax=%d", a.Jmin, a.Jmax)
	}
	// Junk sizes must not collide: amneziawg-go classifies an incoming datagram's
	// message type by its on-the-wire length, so the obfuscated initiation packet
	// (MessageInitiationSize + s1) and response packet (MessageResponseSize + s2)
	// must differ in length. A colliding s1/s2 pair passes config load but is
	// rejected later by the engine's IpcSet ("new init size == new response size");
	// reject it here so the collision fails fast at load, at the right locus. The
	// engine's own MessageInitiationSize (148) and MessageResponseSize (92)
	// constants are used so this check tracks the vendored fork if it ever changes.
	if awgdevice.MessageInitiationSize+a.S1 == awgdevice.MessageResponseSize+a.S2 {
		return fmt.Errorf("amnezia: junk sizes collide — obfuscated init size %d (%d+s1) must differ from response size %d (%d+s2); adjust s1/s2",
			awgdevice.MessageInitiationSize+a.S1, awgdevice.MessageInitiationSize,
			awgdevice.MessageResponseSize+a.S2, awgdevice.MessageResponseSize)
	}
	// Magic headers must be distinct: the receive path classifies a datagram's
	// message type by its header value, so two equal headers make two message
	// types indistinguishable. An all-zero header set is left for applyDefaults;
	// any non-zero header requires a complete, distinct set (a partial set leaves
	// zeros here and is caught as a duplicate).
	if a.H1 != 0 || a.H2 != 0 || a.H3 != 0 || a.H4 != 0 {
		if a.H1 == a.H2 || a.H1 == a.H3 || a.H1 == a.H4 ||
			a.H2 == a.H3 || a.H2 == a.H4 || a.H3 == a.H4 {
			return fmt.Errorf("amnezia: magic headers must be a complete, distinct set, got h1=%d h2=%d h3=%d h4=%d",
				a.H1, a.H2, a.H3, a.H4)
		}
	}
	return nil
}

package reseq

import (
	"net/netip"
	"sync"
	"time"
)

// Clock is the injected time source. Production wires a monotonic wall clock
// (SystemClock); tests wire a hand-advanced fake so ordering, window, and
// timeout behaviour are deterministic with no real sleeps. It is intentionally
// structurally identical to telemetry.Clock so the same fake can drive both.
type Clock interface {
	Now() time.Time
}

// SystemClock is the production Clock backed by the monotonic wall clock.
type SystemClock struct{}

// Now returns the current monotonic time.
func (SystemClock) Now() time.Time { return time.Now() }

// Discontinuity/resync guard tuning. A DATA frame is UNAUTHENTICATED by design
// (internal/frame/frame.go: "DATA/PARITY forgeable by design"), so a garbage
// datagram decoding as KindData (p ~ 1/256) delivers a uniformly-random uint64
// OuterSeq, and a genuine peer PROCESS RESTART resets the peer's outerSeq counter
// to 1. Neither may be trusted to move the release point arbitrarily.
const (
	// resyncFactor (K) bounds how far AHEAD of the release point a single
	// unauthenticated frame is trusted to advance the window as a plausible loss
	// burst. Under bounded cross-path reorder a legitimate frame sits within one
	// window of next; a forward jump up to K windows is still treated as a loss
	// burst (the sound bounded-memory window-advance handles it in O(window)), but
	// a jump of K windows or more is SUSPECT: a single such frame never advances
	// next. K=4 leaves generous headroom above the 1-window reorder bound while
	// capping the release point a single trusted frame can skip to (K-1) windows.
	resyncFactor = 4

	// resyncCorroborate (C) is how many out-of-band frames carrying DISTINCT seqs
	// that mutually span less than one window must be observed before the release
	// point is re-pinned. A genuine peer restart (1,2,3,...) or a consistent
	// long-outage forward jump emits connected, distinct seqs that trivially
	// corroborate. A repeated identical seq does NOT advance the count: a single
	// junk or forged datagram re-delivered — a network duplicate, or a forger
	// replaying one datagram — contributes only ONE distinct seq, so it can never
	// self-corroborate. Corroboration therefore requires C INDEPENDENT junk seqs to
	// land mutually within one window; each is independent in 2^64, so that occurs
	// with probability ~(window/2^64)^(C-1) ~ 1e-32 for C=3 and window=2048 — junk
	// never triggers a resync, while a real discontinuity resyncs after losing at
	// most C-1 frames. Any in-band (near-current) frame resets the run, so ordinary
	// traffic interspersed with rare junk never accumulates a false corroboration.
	resyncCorroborate = 3
)

// Item is one released inner datagram plus the outer source address of the DATA
// frame that carried it. The source travels with the payload so the multipath
// Bind can pin its single virtual endpoint to the FIRST delivered frame's
// source even when that frame was buffered and released out of arrival order.
type Item struct {
	Payload []byte
	Src     netip.AddrPort
}

// slot is one ring cell. A live cell (occupied) holds exactly one buffered DATA
// frame whose OuterSeq maps to this index; seq is retained so a stale cell (an
// already-drained seq that shares the index modulo window) is never mistaken for
// a live one.
type slot struct {
	seq      uint64
	src      netip.AddrPort
	payload  []byte
	occupied bool
}

// Resequencer is a bounded-window, timeout-based receive resequencing buffer. It
// consumes DATA frames tagged with the multipath codec's OWN outer sequence
// number (frame.Data.OuterSeq — never WireGuard's inner counter) arriving out of
// order across paths, and releases the decoded inner datagrams in strictly
// ascending outer-seq order before they reach the WireGuard engine. This absorbs
// multipath reorder entirely in the outer layer so WG's RFC 6479 anti-replay
// filter (window 8128, see docs/p0-findings.md §6) only ever sees monotonically
// increasing inner counters and never drops a legitimately-delivered packet.
//
// Guarantees (see the package tests):
//   - Ordering: released frames are strictly ascending in outer-seq. A frame
//     whose seq is below the release point is dropped, never delivered late, so
//     delivery is monotonic and WG sees no replay-window regression.
//   - Exactly-once: duplicates (same seq re-observed before or after release) are
//     dropped; every deliverable frame is released exactly once.
//   - Bounded memory: at most `window` frames are buffered. A frame at or beyond
//     next+window forces the window to advance (releasing/skipping the tail),
//     so an adversarial reorder/loss trace cannot grow the buffer without bound.
//   - Timeout progress: when the head-of-line seq is missing, buffered frames
//     ahead of the gap are held at most `timeout`; then the gap is skipped
//     (treated as lost) and the run released, rather than stalling forever. Each
//     distinct head-of-line gap gets its OWN full timeout.
//   - Bounded compute: every Observe runs in O(window). No frame — however wild
//     its (unauthenticated, possibly forged) seq — can make the release point
//     advance one seq at a time across a gap of up to 2^64 under the mutex.
//   - Discontinuity resilience: an unauthenticated frame whose seq lies farther
//     than resyncFactor*window from next never moves the release point on its own.
//     A genuine peer restart or long outage — a run of frames carrying DISTINCT
//     seqs that mutually fall within one window — re-pins (resyncs) the release
//     point within a bounded number of frames; uniformly-random junk seqs, and a
//     single junk/forged seq re-delivered any number of times, do not.
//
// Concurrency: every method is guarded by one mutex, so the shared instance is
// safe for the multipath Bind's per-path receive goroutines. The mutex is held
// only for in-memory bookkeeping — never across a syscall — so it does not
// perturb the Bind's lock-free virtual-endpoint fast path or its
// syscall-outside-mutex send discipline.
//
// FEC seam (T24): Observe is the sole ingestion point and is keyed purely by
// outer-seq. An FEC decoder inserted on the receive path recovers missing DATA
// frames from PARITY and feeds each recovered frame's ORIGINAL outer-seq through
// Observe, identically to a natively-received frame — so FEC recovery slots in
// BEFORE resequencing with no change to this type.
type Resequencer struct {
	window  uint64
	timeout time.Duration
	clock   Clock

	mu      sync.Mutex
	started bool   // false until the first Observe pins the initial next
	next    uint64 // lowest outer-seq not yet released
	ring    []slot // len == window; indexed by seq % window
	buf     int    // number of occupied slots

	ready    []Item // FIFO of released items awaiting Pop
	readyPos int    // read cursor into ready (front of the FIFO)

	// Head-of-line timeout: when next is a gap but frames ahead are buffered,
	// waiting is armed with a deadline measured from when the gap first formed.
	waiting  bool
	deadline time.Time

	// Discontinuity/resync guard: the current run of out-of-band (suspect) frames.
	// resyncSeqs holds the DISTINCT suspect seqs seen in the run (a repeated
	// identical seq does not advance corroboration); [resyncLo, resyncHi] is the
	// run's seq span. When resyncSeqs reaches resyncCorroborate distinct seqs the
	// run is deemed a real discontinuity and the release point re-pins (see
	// tryResync). It holds at most resyncCorroborate seqs, so memory stays bounded.
	resyncSeqs []uint64
	resyncLo   uint64
	resyncHi   uint64

	// Diagnostics (read via the accessors; useful for the bounded-memory asserts).
	highWater   int    // max occupied slots ever held
	dropDup     uint64 // frames dropped as duplicates
	dropLate    uint64 // frames dropped as already-past the release point
	dropSuspect uint64 // out-of-band frames dropped while (not yet) corroborating
	skipped     uint64 // seqs skipped (treated lost) by window-advance or timeout
	releasedN   uint64 // frames released for delivery
	resyncs     uint64 // release-point re-pins after a corroborated discontinuity
	rebaselines uint64 // release-point re-baselines forced by a trusted control event (hub failover)
}

// New returns a resequencer buffering at most window outer-seq positions and
// holding a head-of-line-blocked run for at most timeout before skipping the gap.
// window must be positive; timeout may be zero (a missing head seq is skipped as
// soon as the next Observe/Pop advances the clock past the arrival instant).
func New(window uint64, timeout time.Duration, clock Clock) *Resequencer {
	if window == 0 {
		panic("reseq: window must be positive")
	}
	if clock == nil {
		panic("reseq: clock must be non-nil")
	}
	return &Resequencer{
		window:  window,
		timeout: timeout,
		clock:   clock,
		ring:    make([]slot, window),
	}
}

// Observe ingests one DATA frame's inner payload under its outer-seq. It takes
// ownership of payload (the caller must not mutate it afterwards); the multipath
// Bind passes the freshly-decoded frame.Data.Payload, which aliases nothing else.
// src is the outer source address the frame arrived from. Any frames that become
// deliverable are appended to the ready FIFO for Pop.
func (r *Resequencer) Observe(seq uint64, payload []byte, src netip.AddrPort) {
	now := r.clock.Now()
	r.mu.Lock()
	defer r.mu.Unlock()

	if !r.started {
		r.started = true
		r.next = seq
	}

	// Give up on any head-of-line gap whose hold time has elapsed before deciding
	// where this frame lands.
	r.expire(now)

	// Classify the frame against the release window and the discontinuity guard.
	// admit adjusts next (window-advance or resync) when warranted and reports
	// whether the frame now lands inside [next, next+window) and should be placed.
	if !r.admit(seq) {
		return
	}

	cell := &r.ring[seq%r.window]
	if cell.occupied && cell.seq == seq {
		r.dropDup++
		return
	}
	cell.seq = seq
	cell.src = src
	cell.payload = payload
	cell.occupied = true
	r.buf++
	if r.buf > r.highWater {
		r.highWater = r.buf
	}

	r.drain()
	r.arm(now)
}

// ObserveRecovered ingests a payload the FEC decoder reconstructed from parity (T24).
// Unlike Observe it NEVER moves or re-pins the release point: a recovered frame is a
// REPAIR for a past gap, so if it has already fallen below the release point it is
// dropped as too-late, and it can neither window-advance nor corroborate a resync — so
// FEC recovery can never CAUSE the burst loss it exists to prevent (a late batch of K
// recovered seqs below `next` must not be able to dump the live buffer via a backward
// resync). It returns whether the frame was PLACED (landed at or above the release
// point and will be delivered in order); a dropped-late recovered frame returns false,
// which the datapath uses to keep the /metrics recovered counter honest — counting
// frames actually delivered ahead of the release point, not merely reconstructed.
func (r *Resequencer) ObserveRecovered(seq uint64, payload []byte, src netip.AddrPort) bool {
	now := r.clock.Now()
	r.mu.Lock()
	defer r.mu.Unlock()

	if !r.started {
		r.started = true
		r.next = seq
	}
	r.expire(now)

	// The placement window is EXACTLY [next, next+window). A recovered frame below next
	// is too late (drop, and — crucially — never feed the resync guard). One at or beyond
	// next+window would require a window-advance we refuse to perform for a reconstructed
	// frame, since that would skip live seqs on the strength of a repair. Neither branch
	// touches next or the corroboration run.
	if seq < r.next {
		if r.next-seq > r.window {
			r.dropSuspect++
		} else {
			r.dropLate++
		}
		return false
	}
	if seq-r.next >= r.window {
		r.dropLate++
		return false
	}

	cell := &r.ring[seq%r.window]
	if cell.occupied && cell.seq == seq {
		r.dropDup++
		return false // already buffered (a received frame or a prior recovery)
	}
	cell.seq = seq
	cell.src = src
	cell.payload = payload
	cell.occupied = true
	r.buf++
	if r.buf > r.highWater {
		r.highWater = r.buf
	}

	r.drain()
	r.arm(now)
	return true
}

// admit classifies seq against the release window and the discontinuity guard and
// decides whether the frame should be buffered. It returns true when seq now lies
// inside [next, next+window) and should be placed; false (having bumped the
// appropriate drop counter) when the frame is dropped. It may advance next by a
// bounded amount on a plausible loss burst, or re-pin next on a corroborated
// discontinuity. Caller holds r.mu.
func (r *Resequencer) admit(seq uint64) bool {
	if seq < r.next {
		// Below the release point. A frame more than one window below next is
		// impossibly late under bounded reorder — treat it as SUSPECT (a peer
		// restart resets outerSeq to 1, so its frames land here). A frame within a
		// window below next is an ordinary straggler/duplicate.
		if r.next-seq > r.window {
			if r.tryResync(seq) {
				return true
			}
			r.dropSuspect++
			return false
		}
		r.resyncReset() // near-current traffic: not a discontinuity
		r.dropLate++
		return false
	}
	// seq >= next.
	if seq-r.next >= resyncFactor*r.window {
		// Too far ahead to be a plausible loss burst — SUSPECT (garbage-decoded or
		// forged high seq). A single such frame must not advance next.
		if r.tryResync(seq) {
			return true
		}
		r.dropSuspect++
		return false
	}
	// In-window, or a moderate (plausible loss-burst) forward jump: legitimate
	// near-current traffic, so any in-progress discontinuity run is broken.
	r.resyncReset()
	if seq-r.next >= r.window {
		// Beyond the window: advance the release point so the frame fits at the top
		// of the window, releasing buffered frames below the new base in order and
		// skipping the (assumed lost) gaps. This is what bounds memory.
		r.advanceTo(seq - r.window + 1)
	}
	return true
}

// Pop returns the next in-order released inner datagram, or ok=false when none is
// ready. It also advances the head-of-line timeout, so a receive goroutine that
// only drains still makes timeout progress.
func (r *Resequencer) Pop() (Item, bool) {
	now := r.clock.Now()
	r.mu.Lock()
	defer r.mu.Unlock()

	r.expire(now)

	if r.readyPos >= len(r.ready) {
		return Item{}, false
	}
	it := r.ready[r.readyPos]
	r.ready[r.readyPos] = Item{} // release the payload reference
	r.readyPos++
	if r.readyPos >= len(r.ready) {
		// FIFO drained: reset to reuse the backing array, keeping it bounded.
		r.ready = r.ready[:0]
		r.readyPos = 0
	}
	return it, true
}

// drain releases the contiguous run starting at next into the ready FIFO. Caller
// holds r.mu.
func (r *Resequencer) drain() {
	for {
		cell := &r.ring[r.next%r.window]
		if !cell.occupied || cell.seq != r.next {
			return
		}
		r.release(cell)
		r.next++
	}
}

// advanceTo moves next up to target, releasing any occupied cell it passes (in
// ascending order) and counting the empty positions as skipped (lost) seqs. It is
// O(window), NEVER O(target-next): all occupied cells live in [next, next+window),
// so once next reaches next+window the remaining gap is provably empty and is
// closed by arithmetic rather than iterated. Caller holds r.mu; target must be
// > next.
func (r *Resequencer) advanceTo(target uint64) {
	// Only [next, next+window) can hold occupied cells; iterate at most that far.
	limit := target
	if limit > r.next+r.window {
		limit = r.next + r.window
	}
	for r.next < limit {
		cell := &r.ring[r.next%r.window]
		if cell.occupied && cell.seq == r.next {
			r.release(cell)
		} else {
			r.skipped++
		}
		r.next++
	}
	if r.next < target {
		// The remaining gap [next, target) is entirely empty — no occupied cell can
		// live a full window ahead of the old release point. Close it by arithmetic.
		r.skipped += target - r.next
		r.next = target
	}
}

// release moves one occupied cell's payload into the ready FIFO and clears it.
// Caller holds r.mu.
func (r *Resequencer) release(cell *slot) {
	r.ready = append(r.ready, Item{Payload: cell.payload, Src: cell.src})
	cell.occupied = false
	cell.payload = nil
	r.buf--
	r.releasedN++
}

// expire skips a head-of-line gap whose hold time has elapsed: it jumps next to
// the smallest buffered seq (treating the intervening seqs as lost) and releases
// the now-contiguous run. Caller holds r.mu.
func (r *Resequencer) expire(now time.Time) {
	if !r.waiting || now.Before(r.deadline) {
		return
	}
	minSeq, ok := r.smallestBuffered()
	if !ok {
		r.waiting = false
		return
	}
	// Skip the lost gap [next, minSeq), then release from minSeq onward.
	for r.next < minSeq {
		r.skipped++
		r.next++
	}
	r.drain()
	// Clear the armed state BEFORE re-arming so that a distinct SECOND gap exposed
	// by this release gets its own full timeout rather than inheriting this gap's
	// already-elapsed deadline (which would skip it with ~zero hold).
	r.waiting = false
	r.arm(now)
}

// arm (re)evaluates the head-of-line timeout after a change. When next is a gap
// but buffered frames sit ahead of it, it starts the hold clock (only if not
// already running, so the deadline measures from when the gap first formed).
// Otherwise it disarms. Caller holds r.mu.
func (r *Resequencer) arm(now time.Time) {
	cell := &r.ring[r.next%r.window]
	headPresent := cell.occupied && cell.seq == r.next
	if !headPresent && r.buf > 0 {
		if !r.waiting {
			r.waiting = true
			r.deadline = now.Add(r.timeout)
		}
	} else {
		r.waiting = false
	}
}

// tryResync feeds one out-of-band (suspect) seq into the discontinuity guard. It
// re-pins the release point ONLY after resyncCorroborate DISTINCT suspect seqs
// whose values mutually span less than one window (a genuine peer restart or long
// outage emits connected, distinct seqs that corroborate; uniformly-random junk
// seqs, each independent in 2^64, do not, and a single junk/forged seq re-delivered
// contributes only ONE distinct value so it can never self-corroborate). It
// returns true and performs the resync when the corroboration threshold is met —
// re-pinning next to the triggering seq so the caller places it as the new head
// and delivery resumes immediately, without a phantom gap or an extra timeout —
// and false while still collecting or when the seq fails to corroborate the
// current run. Caller holds r.mu.
func (r *Resequencer) tryResync(seq uint64) bool {
	if len(r.resyncSeqs) == 0 || r.spanExceeds(seq) {
		// Start (or restart) the run at this seq: it does not corroborate the
		// current run, so it becomes the anchor of a fresh one.
		r.resyncLo, r.resyncHi = seq, seq
		r.resyncSeqs = append(r.resyncSeqs[:0], seq)
		return false
	}
	if r.runContains(seq) {
		// A repeated identical seq does NOT advance corroboration: a lone junk or
		// forged datagram re-delivered must not count as independent corroboration.
		return false
	}
	if seq < r.resyncLo {
		r.resyncLo = seq
	}
	if seq > r.resyncHi {
		r.resyncHi = seq
	}
	r.resyncSeqs = append(r.resyncSeqs, seq)
	if len(r.resyncSeqs) < resyncCorroborate {
		return false
	}
	// Corroborated discontinuity: re-pin to the triggering seq and resume delivery.
	r.resync(seq)
	return true
}

// runContains reports whether seq is already one of the distinct suspect seqs in
// the current corroboration run. The run holds at most resyncCorroborate seqs, so
// this scan is O(C). Caller holds r.mu.
func (r *Resequencer) runContains(seq uint64) bool {
	for _, s := range r.resyncSeqs {
		if s == seq {
			return true
		}
	}
	return false
}

// spanExceeds reports whether adding seq to the current corroboration run would
// make its seq span reach or exceed one window (i.e. seq does not mutually fall
// within one window of the run so far). Caller holds r.mu.
func (r *Resequencer) spanExceeds(seq uint64) bool {
	lo, hi := r.resyncLo, r.resyncHi
	if seq < lo {
		lo = seq
	}
	if seq > hi {
		hi = seq
	}
	return hi-lo >= r.window
}

// resync re-pins the release point to base after a confirmed discontinuity,
// discarding all buffered frames (they belong to the pre-discontinuity stream) in
// O(window). The already-released FIFO is untouched — those were legitimate prior
// deliveries. Caller holds r.mu.
func (r *Resequencer) resync(base uint64) {
	for i := range r.ring {
		r.ring[i] = slot{}
	}
	r.buf = 0
	r.next = base
	r.waiting = false
	r.resyncReset()
	r.resyncs++
}

// resyncReset abandons the current corroboration run. Caller holds r.mu.
func (r *Resequencer) resyncReset() {
	r.resyncSeqs = r.resyncSeqs[:0]
	r.resyncLo = 0
	r.resyncHi = 0
}

// Rebaseline discards the buffered (pre-switch) frames and UNPINS the release
// point so the NEXT Observe re-anchors `next` to that frame's outer-seq, exactly as
// if the stream had just started. It exists for the edge-side HUB FAILOVER (T57): a
// concentrator switch changes the DATA-frame SENDER, and the standby is a separate
// process whose outer-seq restarts near 1 — far below the release point the prior
// hub's high-rate stream advanced `next` to. The unauthenticated tryResync path
// cannot rescue this in time: it needs resyncCorroborate (3) distinct low seqs
// within one window, but a freshly re-handshaking standby emits only ~1 DATA frame
// (the handshake response) per RekeyTimeout, so corroboration falls outside the
// failover window and the response is dropped as SUSPECT — the tunnel never
// re-establishes (defect D32). Unlike a DATA frame (forgeable by design, hence the
// corroboration guard), THIS re-pin is driven by a TRUSTED control event — the
// operator-configured ordered-endpoint switch, above the unauthenticated wire — so
// re-anchoring on the next single frame is sound. Buffered frames (from the dead
// prior hub) are discarded in O(window); the already-released FIFO of prior
// legitimate deliveries is untouched. Idempotent and safe before the first Observe
// (started stays false). Takes r.mu; the caller must NOT hold it.
func (r *Resequencer) Rebaseline() {
	r.mu.Lock()
	defer r.mu.Unlock()
	for i := range r.ring {
		r.ring[i] = slot{}
	}
	r.buf = 0
	r.started = false
	r.waiting = false
	r.resyncReset()
	r.rebaselines++
}

// smallestBuffered scans the ring for the lowest occupied seq at or above next.
// All occupied seqs lie in [next, next+window), so this is bounded by window and
// runs only on the (rare) timeout path. Caller holds r.mu.
func (r *Resequencer) smallestBuffered() (uint64, bool) {
	best := uint64(0)
	found := false
	for i := range r.ring {
		c := &r.ring[i]
		if c.occupied && c.seq >= r.next && (!found || c.seq < best) {
			best = c.seq
			found = true
		}
	}
	return best, found
}

// Buffered reports the number of frames currently held (not yet released). It is
// always <= window, which the bounded-memory tests assert.
func (r *Resequencer) Buffered() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.buf
}

// Pending reports the number of released-but-not-yet-popped items in the FIFO.
func (r *Resequencer) Pending() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return len(r.ready) - r.readyPos
}

// HighWater reports the maximum number of frames ever buffered simultaneously.
func (r *Resequencer) HighWater() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.highWater
}

// Stats is a snapshot of the resequencer's cumulative counters.
type Stats struct {
	Released       uint64 // frames released for delivery
	DroppedDup     uint64 // frames dropped as duplicates
	DroppedOld     uint64 // frames dropped as already-past the release point
	DroppedSuspect uint64 // out-of-band frames dropped while (not yet) corroborating
	Skipped        uint64 // seqs skipped (lost) by window-advance or timeout
	Resyncs        uint64 // release-point re-pins after a corroborated discontinuity
	Rebaselines    uint64 // release-point re-baselines forced by a trusted control event (hub failover)
}

// Stats returns a snapshot of the cumulative counters.
func (r *Resequencer) Stats() Stats {
	r.mu.Lock()
	defer r.mu.Unlock()
	return Stats{
		Released:       r.releasedN,
		DroppedDup:     r.dropDup,
		DroppedOld:     r.dropLate,
		DroppedSuspect: r.dropSuspect,
		Skipped:        r.skipped,
		Resyncs:        r.resyncs,
		Rebaselines:    r.rebaselines,
	}
}

// Package device brings a wanbond tunnel up from a validated configuration: it
// creates the TUN interface, drives the embedded amneziawg-go engine over the
// multipath Bind, and applies the WireGuard (and, when configured, amnezia
// obfuscation) parameters via the engine's UAPI. It owns ONLY the tunnel engine
// — interface addressing and routing are left to the operator (systemd/wg-quick
// style), so the daemon stays free of privileged shell-outs. The interface name
// is exposed via Tunnel.Name for that external configuration step.
package device

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"reflect"
	"strings"
	"sync"
	"time"

	awgdevice "github.com/amnezia-vpn/amneziawg-go/device"
	"github.com/amnezia-vpn/amneziawg-go/tun"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/bind"
	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/metrics"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// metricsShutdownTimeout bounds the graceful shutdown of the /metrics endpoint on
// Close (and on a reload that rebinds it). The endpoint is loopback-only with no
// long-lived scrapes, so this is comfortably generous.
const metricsShutdownTimeout = 2 * time.Second

// defaultTUNName is the requested interface name; the kernel honours it unless it
// collides (it never does across the edge and concentrator network namespaces).
const defaultTUNName = "wanbond0"

// tunMTU is the tunnel (TUN) MTU for a config: the default path MTU minus the
// IP+UDP, outer DATA-frame, and WireGuard transport overheads, so a full-MTU inner
// packet never fragments on the wire (see internal/bind mtu.go and docs/p1-mtu.md).
// This is smaller than the plain-WireGuard 1420 because the bonding layer adds its
// own outer DATA frame per datagram; with FEC enabled it is a further
// bind.FECParityMTUPenalty smaller so a full-size PARITY frame also fits the path MTU
// (T24) rather than fragmenting.
func tunMTU(cfg *config.Config) int {
	return bind.InnerMTU(bind.DefaultPathMTU, cfg.FEC.Enabled)
}

// Tunnel is a running wanbond tunnel: the amneziawg engine, its TUN, and the
// multipath Bind. Close tears all three down.
type Tunnel struct {
	dev  *awgdevice.Device
	tun  tun.Device
	name string
	// bind is the multipath Bind the engine drives; Reload calls its runtime
	// AddPath/RemovePath to apply a config-reload path diff (T30).
	bind *bind.Multipath
	// cfg is the configuration the RUNNING tunnel reflects: the boot config, its path
	// set updated on each successful Reload to the current membership (survivors keep
	// their original parameters — a membership-only reload does not re-apply modified
	// path parameters or non-path fields). Reload diffs the next desired config against
	// it to warn about changes it cannot apply. Guarded by reloadMu.
	cfg *config.Config
	// reloadMu serializes Reload against itself (SIGHUP handlers), guarding cfg.
	reloadMu sync.Mutex
	// log is the device-component logger, retained for Reload diagnostics.
	log log.Logger
	// stopProbes halts the per-path probe cadence loop (T37). Close calls it before
	// tearing the engine down so emission stops before the sockets close. It is
	// idempotent and never nil (a no-op when the bind runs without probers).
	stopProbes func()
	// stopReconcile halts the background deferred-path reconcile loop (T55): it retries
	// binding the paths a tolerant Open left DOWN as their addresses appear. Close calls
	// it before tearing the engine down so no reconcile races the socket close. It is
	// idempotent and never nil (a no-op when the bind runs without probers / never defers).
	stopReconcile func()
	// stopHubFailover halts the edge-side hub-failover monitor loop (T57): it watches the
	// per-path liveness plane and, on hub loss (all paths to the active concentrator DOWN),
	// advances to the next ordered peer endpoint, repoints the bond's remote, and initiates
	// a fresh WG re-handshake. Close calls it before tearing the engine down. It is
	// idempotent and never nil (a no-op on the concentrator, or an edge with a single
	// concentrator endpoint, or a bind without the probe transport).
	stopHubFailover func()
	// amnezia is the obfuscation profile this tunnel holds against the
	// process-global amnezia guard (see amneziaGuard); Close releases it.
	amnezia     config.Amnezia
	releaseOnce sync.Once

	// metricsSrc is the live metrics.Source over the Bind; it is stable for the tunnel's
	// life (the Bind pointer never changes), so a reload that rebinds the endpoint reuses
	// the SAME Source — its derived-throughput last-sample state survives the rebind.
	metricsSrc metrics.Source
	// metricsSrv is the running /metrics endpoint, nil when [metrics].listen is empty.
	// It is (re)assigned by applyMetricsLocked and read by Close; both hold reloadMu, so
	// a SIGHUP-driven rebind never races shutdown. metricsListen mirrors the address it
	// is bound to so a reload can detect a listen change without inspecting the server.
	metricsSrv    *metrics.Server
	metricsListen string
}

// SINGLE-ENGINE-PER-PROCESS INVARIANT (defect D2).
//
// amneziawg-go stores the amnezia magic-header message types in PACKAGE-GLOBAL
// variables — device.MessageInitiationType, MessageResponseType,
// MessageCookieReplyType, MessageTransportType. (*device.Device).IpcSet assigns
// them (in handlePostConfig) from a configured engine's profile, and
// (*device.Device).Close restores them to the WireGuard defaults (in
// resetProtocol) UNCONDITIONALLY — closing ANY engine, plain or configured,
// reverts the process-global message types to their defaults.
//
// Two consequences make a CONFIGURED (amnezia) engine require PROCESS
// EXCLUSIVITY:
//   - a second configured engine would overwrite the first engine's message-type
//     framing at IpcSet; and even with the SAME profile, closing the first engine
//     runs resetProtocol and reverts the globals to defaults under the second,
//     still-live engine, silently dropping its tunnel to plain-WireGuard framing.
//   - closing ANY other engine — a PLAIN (unconfigured) one included — runs
//     resetProtocol and resets the globals out from under a live configured engine.
//
// So the rule wanbond ASSERTS (rather than vendor-patching the fork) is:
//   - a configured engine may come up only when NO other engine is live, and
//   - no engine (plain or configured) may come up while a configured engine is live.
//
// PLAIN engines may coexist with each other: they never set the globals, and
// resetProtocol on their Close only restores the defaults they already use, so it
// is idempotent among them. wanbond runs exactly one tunnel per process, so the
// guard only ever trips on genuine misuse.
type amneziaGuard struct {
	mu         sync.Mutex
	plainLive  int  // number of live plain-WireGuard (unconfigured) engines
	configLive bool // whether a configured (amnezia) engine is live (at most one)
}

// globalAmneziaGuard enforces the single-amnezia-engine-per-process invariant for
// every Tunnel brought up in this process.
var globalAmneziaGuard amneziaGuard

// acquire registers an about-to-start engine against the process-exclusivity rule
// (see amneziaGuard). A configured (amnezia) engine is admitted only when NO other
// engine is live. A plain engine is admitted only when no configured engine is
// live; plain engines may coexist with one another. The caller must release the
// SAME profile exactly once when the engine is torn down (plain engines included —
// release is no longer a no-op for them).
func (g *amneziaGuard) acquire(a config.Amnezia) error {
	g.mu.Lock()
	defer g.mu.Unlock()
	if a.Configured() {
		if g.configLive || g.plainLive > 0 {
			return fmt.Errorf("device: refusing to start an amnezia-configured engine while another engine is live: " +
				"amneziawg-go keeps the magic-header message types in process-global state and resets them to defaults on ANY engine's Close, " +
				"so a configured engine requires process exclusivity — at most one, with no other engine alongside it (D2)")
		}
		g.configLive = true
		return nil
	}
	if g.configLive {
		return fmt.Errorf("device: refusing to start a second engine while an amnezia-configured engine is live: " +
			"closing this engine would reset amneziawg-go's process-global message types to defaults under the live amnezia tunnel (D2)")
	}
	g.plainLive++
	return nil
}

// release drops an engine's hold on the guard. A configured engine clears the
// single configured slot; a plain engine decrements the live plain count.
func (g *amneziaGuard) release(a config.Amnezia) {
	g.mu.Lock()
	defer g.mu.Unlock()
	if a.Configured() {
		g.configLive = false
		return
	}
	if g.plainLive > 0 {
		g.plainLive--
	}
}

// Up creates the TUN, wires the multipath Bind into the amneziawg engine,
// applies the crypto configuration from cfg, and brings the device up. The same
// path drives both roles; the role only changes which UAPI fields cfg carries
// (the concentrator sets listen_port; the edge sets each peer's endpoint).
func Up(cfg *config.Config, lg log.Logger) (*Tunnel, error) {
	clg := lg.Component("device")

	tunDev, err := tun.CreateTUN(defaultTUNName, tunMTU(cfg))
	if err != nil {
		return nil, fmt.Errorf("device: create TUN: %w", err)
	}
	name, err := tunDev.Name()
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: read TUN name: %w", err)
	}

	// Claim the single-amnezia-engine-per-process invariant (D2) BEFORE IpcSet
	// assigns amneziawg-go's process-global message-type state. On any failure
	// below, ok stays false and the deferred release returns the hold; the
	// successful path transfers the hold to the returned Tunnel.
	if err := globalAmneziaGuard.acquire(cfg.Amnezia); err != nil {
		_ = tunDev.Close()
		return nil, err
	}
	ok := false
	defer func() {
		if !ok {
			globalAmneziaGuard.release(cfg.Amnezia)
		}
	}()

	// One live *telemetry.Prober per path drives on-wire liveness. The SAME prober
	// values back the scheduler's PathHealth AND the bind's probe transport, so the
	// liveness the probe loop measures is exactly the liveness the scheduler selects
	// on (T37 replaces the sched.AlwaysUp placeholder here).
	scheduler, probers, newProber, err := buildScheduler(cfg, clg)
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: build scheduler: %w", err)
	}
	mpBind, err := bind.NewMultipath(cfg.Paths, cfg.PSK, scheduler, probers, newProber, fecConfig(cfg.FEC), adaptiveFECConfig(cfg.FEC), cfg.Amnezia)
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: build multipath bind: %w", err)
	}
	dev := awgdevice.NewDevice(tunDev, mpBind, engineLogger(clg, cfg.Log.Level))

	uapi, err := uapiConfig(cfg)
	if err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: build UAPI config: %w", err)
	}
	if err := dev.IpcSet(uapi); err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: apply UAPI config: %w", err)
	}
	if err := dev.Up(); err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: bring up: %w", err)
	}

	// The engine has opened the bind (dev.Up → BindUpdate → Open), so the per-path
	// sockets exist: start the probe cadence now. Close stops it before dev.Close.
	// The interval is the SINGLE-SOURCE-OF-TRUTH telemetry default, which also arms
	// the bind's receive-path liveness sweep throttle (D15).
	stopProbes := mpBind.StartProbeLoop(telemetry.DefaultProbeInterval)
	// Start the background deferred-path reconciler alongside probing (T55): a path the
	// tolerant Open left DOWN (its source_addr not yet assignable — a 5G modem without a
	// lease at boot) is retried and promoted to a live path as its address appears,
	// WITHOUT a tunnel restart. Close stops it before dev.Close, like the probe loop.
	stopReconcile := mpBind.StartReconcileLoop(bind.DefaultReconcileInterval)
	// Start the edge-side hub-failover monitor (T57): on hub loss (every path to the
	// active concentrator DOWN) it advances to the next ordered peer endpoint, repoints the
	// bond's remote, and re-handshakes. A no-op on the concentrator, a single-concentrator
	// edge, or a bind without the probe transport. Started AFTER dev.Up so the engine peer
	// the re-handshake looks up exists (IpcSet added it above). Close stops it before
	// dev.Close, like the probe/reconcile loops.
	stopHubFailover := startHubFailover(cfg, mpBind, probers, dev, clg)

	t := &Tunnel{
		dev: dev, tun: tunDev, name: name, bind: mpBind, cfg: cfg, log: clg,
		stopProbes: stopProbes, stopReconcile: stopReconcile, stopHubFailover: stopHubFailover, amnezia: cfg.Amnezia,
		// The Source reads live per-path counters/telemetry from the Bind and derives
		// throughput from the byte-counter delta between scrapes (see metricsSource). It is
		// built unconditionally (cheap) so a reload that later turns [metrics].listen ON has
		// a Source ready; the endpoint itself is started only when a listen is configured.
		metricsSrc: newMetricsSource(mpBind, telemetry.SystemClock{}),
	}

	// Stand up the /metrics endpoint when configured. A non-loopback listen is refused
	// by metrics.NewServer (fail fast) — surface it as an Up failure rather than booting
	// a tunnel that silently exposes per-path operational data off-host.
	t.reloadMu.Lock()
	err = t.applyMetricsLocked(cfg.Metrics.Listen)
	t.reloadMu.Unlock()
	if err != nil {
		// The tunnel is fully constructed and holds the amnezia guard, so transfer that
		// ownership to it (ok=true) BEFORE tearing it down: t.Close releases the guard via
		// releaseOnce, and suppressing the !ok defer avoids a double release. t.Close also
		// stops the probe loop and closes the engine/TUN.
		ok = true
		t.Close()
		return nil, fmt.Errorf("device: start metrics endpoint: %w", err)
	}

	ok = true
	clg.Info("tunnel up", "interface", name, "role", string(cfg.Role))
	return t, nil
}

// applyMetricsLocked reconciles the running /metrics endpoint to listen: it starts the
// endpoint when one is desired and none runs, stops it when listen is empty, and rebinds
// (stop old, start new) when the address changed. It is idempotent for an unchanged
// address. The Source is reused across a rebind so its derived-throughput state is not
// reset. The caller MUST hold reloadMu (Up and Reload both do), which also serializes it
// against Close reading metricsSrv. On a NewServer/refuse error the previous server is
// left running untouched, so a bad reload never drops a working endpoint.
func (t *Tunnel) applyMetricsLocked(listen string) error {
	if listen == t.metricsListen {
		return nil
	}
	if listen == "" {
		t.stopMetricsLocked()
		return nil
	}
	srv, err := metrics.NewServer(listen, t.metricsSrc, t.log)
	if err != nil {
		return err
	}
	t.stopMetricsLocked()
	srv.Start()
	t.metricsSrv = srv
	t.metricsListen = listen
	return nil
}

// stopMetricsLocked gracefully shuts the running endpoint down (if any) and clears the
// bookkeeping. Caller holds reloadMu.
func (t *Tunnel) stopMetricsLocked() {
	if t.metricsSrv == nil {
		return
	}
	ctx, cancel := context.WithTimeout(context.Background(), metricsShutdownTimeout)
	defer cancel()
	if err := t.metricsSrv.Close(ctx); err != nil {
		t.log.Warn("metrics endpoint shutdown error", "error", err.Error())
	}
	t.metricsSrv = nil
	t.metricsListen = ""
}

// Reload applies a reloaded configuration to the RUNNING tunnel by diffing its
// path set against the live one and adding/removing paths at runtime (T30), WITHOUT
// tearing the tunnel down: the WG session, the surviving paths, and in-flight
// resequencing are all preserved. cfg is assumed already validated (config.Load
// fails fast on a bad file, so a bad reload never reaches here and never disturbs
// the running tunnel). Only the path set is diffed — the crypto/amnezia/role fields
// are fixed for the life of the process and a reload does not re-key the engine.
//
// New paths are added BEFORE absent ones are removed, so a failed addition aborts
// with every existing path still in service. Diffing is by name: a path present in
// both sets is left untouched (its source/dest parameters are not re-read).
//
// A membership-only reload CANNOT apply every kind of change: a same-name path whose
// source/dest changed, a path REORDER (index 0 is the preferred primary, so a reorder
// is a priority change), and every non-path field (psk, wireguard, amnezia, role, log,
// metrics) are all out of scope for T30. Rather than silently diverge from the file,
// Reload logs an EXPLICIT WARNING per ignored change (reloadWarnings) so the operator
// knows exactly what was dropped; only the path-membership add/remove is applied.
func (t *Tunnel) Reload(cfg *config.Config) error {
	t.reloadMu.Lock()
	defer t.reloadMu.Unlock()

	for _, w := range reloadWarnings(t.cfg, cfg) {
		t.log.Warn("reload: ignored config change (path-membership reload only)", "change", w)
	}

	// Rebind the /metrics endpoint if its listen address changed (T23). This is one of
	// the few non-path fields a reload DOES apply: the endpoint is external to the WG
	// session and the Bind, so restarting it disturbs neither. applyMetricsLocked reuses
	// the tunnel's stable Source (its derived-throughput state survives), and on a refuse
	// (e.g. a newly non-loopback address) leaves the previous endpoint running and fails
	// the reload — the running tunnel is never disturbed. Applied BEFORE the path diff so
	// a metrics-refuse aborts before any membership change.
	if cfg.Metrics.Listen != t.metricsListen {
		if err := t.applyMetricsLocked(cfg.Metrics.Listen); err != nil {
			return fmt.Errorf("device: reload metrics endpoint: %w", err)
		}
		t.log.Info("reload: metrics endpoint rebound", "listen", cfg.Metrics.Listen)
	}

	add, remove := diffPaths(t.bind.PathNames(), cfg.Paths)
	for _, def := range add {
		if err := t.bind.AddPath(def); err != nil {
			return fmt.Errorf("device: reload add path %q: %w", def.Name, err)
		}
		t.log.Info("reload: path added", "path", def.Name)
	}
	for _, name := range remove {
		if err := t.bind.RemovePath(name); err != nil {
			return fmt.Errorf("device: reload remove path %q: %w", name, err)
		}
		t.log.Info("reload: path removed", "path", name)
	}
	// Advance the running config to the membership now in service. Survivors keep their
	// ORIGINAL parameters and all non-path fields stay as booted (the ignored changes
	// were not applied), so a subsequent identical reload re-warns about a still-diverged
	// file rather than silently accepting it. Metrics.Listen is carried to the applied
	// value so a subsequent reload diffs against the endpoint actually running.
	t.cfg = runningConfig(t.cfg, add, remove)
	t.cfg.Metrics.Listen = t.metricsListen
	return nil
}

// reloadWarnings compares the desired config against the currently-running one and
// returns one human-readable warning per change a path-membership-only reload (T30)
// cannot apply: a modified same-name path (source/dest), a path reorder, and any
// non-path field. Membership add/remove is NOT reported here — it is applied. Full
// modify-support is out of scope; SILENCE is not — the operator must be told what was
// ignored. It is a pure function so the warning set is unit-testable.
func reloadWarnings(live, desired *config.Config) []string {
	var w []string

	if live.Role != desired.Role {
		w = append(w, fmt.Sprintf("role %q -> %q", live.Role, desired.Role))
	}
	if !reflect.DeepEqual(live.PSK, desired.PSK) {
		w = append(w, "psk changed")
	}
	if !reflect.DeepEqual(live.WireGuard, desired.WireGuard) {
		w = append(w, "wireguard section changed")
	}
	if !reflect.DeepEqual(live.Amnezia, desired.Amnezia) {
		w = append(w, "amnezia section changed")
	}
	if !reflect.DeepEqual(live.Log, desired.Log) {
		w = append(w, "log section changed")
	}
	// NOTE: a Metrics change is NOT warned here — unlike the other non-path fields, the
	// reload APPLIES it by rebinding the /metrics endpoint (see Reload). Warning about a
	// change that is honoured would misinform the operator.

	// Same-name paths whose parameters changed: diffPaths matches by name only, so a
	// modified source/dest on an existing path is otherwise silently dropped.
	liveByName := make(map[string]config.Path, len(live.Paths))
	for _, p := range live.Paths {
		liveByName[p.Name] = p
	}
	for _, d := range desired.Paths {
		l, ok := liveByName[d.Name]
		if !ok {
			continue // a genuinely new path is added, not ignored
		}
		if l.SourceAddr != d.SourceAddr || l.DestAddr != d.DestAddr {
			w = append(w, fmt.Sprintf("path %q source/dest changed — the running path keeps its original binding", d.Name))
		}
	}

	if reordered(live.Paths, desired.Paths) {
		w = append(w, "path priority order changed (reorder) — the running order is unchanged")
	}
	return w
}

// reordered reports whether the paths common to BOTH slices appear in a different
// relative order in desired than in live. The common subsequence has the same length
// on both sides (it is the name intersection), so a positional mismatch is a reorder.
func reordered(live, desired []config.Path) bool {
	desiredNames := make(map[string]struct{}, len(desired))
	for _, p := range desired {
		desiredNames[p.Name] = struct{}{}
	}
	liveNames := make(map[string]struct{}, len(live))
	for _, p := range live {
		liveNames[p.Name] = struct{}{}
	}
	var liveCommon, desiredCommon []string
	for _, p := range live {
		if _, ok := desiredNames[p.Name]; ok {
			liveCommon = append(liveCommon, p.Name)
		}
	}
	for _, p := range desired {
		if _, ok := liveNames[p.Name]; ok {
			desiredCommon = append(desiredCommon, p.Name)
		}
	}
	for i := range liveCommon {
		if liveCommon[i] != desiredCommon[i] {
			return true
		}
	}
	return false
}

// runningConfig advances the running config to the membership the bind now serves:
// the survivors (live paths not removed, keeping their ORIGINAL parameters and order)
// followed by the added paths (their new parameters). Non-path fields are carried over
// unchanged — a membership-only reload does not re-apply them. It mirrors the m.defs
// order the bind rebuilds on a Close→Open (survivors-in-order, then appended adds).
func runningConfig(live *config.Config, add []config.Path, remove []string) *config.Config {
	removeSet := make(map[string]struct{}, len(remove))
	for _, n := range remove {
		removeSet[n] = struct{}{}
	}
	paths := make([]config.Path, 0, len(live.Paths)+len(add))
	for _, p := range live.Paths {
		if _, gone := removeSet[p.Name]; !gone {
			paths = append(paths, p)
		}
	}
	paths = append(paths, add...)
	running := *live
	running.Paths = paths
	return &running
}

// diffPaths computes, by name, which desired paths are not yet live (to add) and
// which live paths are no longer desired (to remove). It is a pure function so the
// reload diff is unit-testable without a running engine.
func diffPaths(live []string, desired []config.Path) (add []config.Path, remove []string) {
	liveSet := make(map[string]struct{}, len(live))
	for _, n := range live {
		liveSet[n] = struct{}{}
	}
	desiredSet := make(map[string]struct{}, len(desired))
	for _, p := range desired {
		desiredSet[p.Name] = struct{}{}
		if _, ok := liveSet[p.Name]; !ok {
			add = append(add, p)
		}
	}
	for _, n := range live {
		if _, ok := desiredSet[n]; !ok {
			remove = append(remove, n)
		}
	}
	return add, remove
}

// defaultFailbackDwell is how long a recovered higher-priority path must stay up
// before egress fails BACK to it, damping flap-induced thrash (T15 hysteresis).
// Unlike the probe-cadence/liveness thresholds (which are the shared
// telemetry.Default* single source of truth, D16), the failback dwell is not part
// of the failover-recovery budget — failover to a backup is instant — so it stays a
// device-local constant.
const defaultFailbackDwell = 5 * time.Second

// fecConfig maps the validated [fec] config block onto the fec.Config the multipath
// Bind consumes (T24), or returns nil when FEC is disabled so the Bind runs the
// datapath with no parity plane. The ratio was already range-checked in config
// validation; the Bind re-validates defensively.
func fecConfig(f config.FEC) *fec.Config {
	if !f.Enabled {
		return nil
	}
	return &fec.Config{
		DataShards:   f.DataShards,
		ParityShards: f.ParityShards,
		Deadline:     f.Deadline,
	}
}

// adaptiveFECConfig maps the [fec] block onto the adaptive controller config the multipath
// Bind drives (T29), or returns nil when FEC is disabled or the block did not opt into
// adaptive mode — in which case the Bind runs the fixed-ratio plane (T24) unchanged. The
// controller uses the simulation-proven default control law (internal/adaptivefec,
// DefaultConfig), with only the group geometry pinned to the configured ratio: DataShards
// (K) is the FEC data_shards and MaxParity (the parity CEILING) is the FEC parity_shards,
// which the receiver's decoder is built at. The Bind re-validates and cross-checks these
// against the FEC config defensively.
func adaptiveFECConfig(f config.FEC) *adaptivefec.Config {
	if !f.Enabled || !f.Adaptive {
		return nil
	}
	c := adaptivefec.DefaultConfig()
	c.DataShards = f.DataShards
	c.MaxParity = f.ParityShards
	// Exactly one sizing mode is active (config load enforces mutual exclusion): in the
	// residual-SLA mode f.SafetyFactor is 0 and f.TargetResidual drives M; in the legacy
	// mode f.TargetResidual is 0 and f.SafetyFactor (defaulted at load) drives M.
	c.SafetyFactor = f.SafetyFactor
	c.TargetResidual = f.TargetResidual
	return &c
}

// buildScheduler constructs one live *telemetry.Prober per path and the P1
// active-backup send scheduler over them, in cfg.Paths' configured priority order
// (index 0 = the preferred primary). The returned probers ARE the scheduler's
// PathHealth sources (a *Prober is internally synchronized, satisfying the
// PathHealth concurrency contract — a bare *Liveness would not) and are handed to
// the bind so the probe transport drives the very same liveness the scheduler
// selects on. This replaces the T15 sched.AlwaysUp placeholder with real on-wire
// failover (T37).
func buildScheduler(cfg *config.Config, lg log.Logger) (sched.Scheduler, []*telemetry.Prober, bind.ProberFactory, error) {
	clock := telemetry.SystemClock{}
	proberCfg := telemetry.ProberConfig{
		LossWindow: telemetry.DefaultLossWindow,
		Liveness: telemetry.LivenessConfig{
			DownAfter:        telemetry.DefaultDownAfter,
			UpAfterSuccesses: telemetry.DefaultUpSuccesses,
		},
	}
	// One random per-boot session id shared by every path's Prober (it identifies
	// this boot, not the path): a peer restart presents a new session id that resets
	// the surviving responder's anti-replay high-water so liveness recovers (T38, D12).
	// A runtime-added path (T30) reuses the SAME session id, so its probes join this
	// boot's stream and the peer's reflector adopts them without a challenge reset.
	sessionID, err := telemetry.NewSessionID(rand.Reader)
	if err != nil {
		return nil, nil, nil, err
	}
	// newProber mints one path's Prober with the shared session/config/clock. It is
	// the single construction point for boot-time AND runtime paths, so both measure
	// liveness identically.
	newProber := func(name string, id uint8) *telemetry.Prober {
		return telemetry.NewProber(name, id, sessionID, cfg.PSK, proberCfg, clock, lg)
	}
	probers := make([]*telemetry.Prober, len(cfg.Paths))
	health := make([]sched.PathHealth, len(cfg.Paths))
	quality := make([]sched.PathQuality, len(cfg.Paths))
	for i := range cfg.Paths {
		probers[i] = newProber(cfg.Paths[i].Name, uint8(i))
		health[i] = probers[i]
		quality[i] = probers[i]
	}
	// Policy is a config choice: active-backup (P1, default) or the T21 weighted-
	// aggregation policy. Both consume the SAME per-path *Prober set — a *Prober
	// satisfies BOTH PathHealth (liveness) and PathQuality (RTT/loss Estimate) — so the
	// probe transport drives the very liveness/quality the scheduler selects on, and the
	// swap is behind config with no Bind change.
	scheduler, err := selectScheduler(cfg, health, quality, clock, lg)
	if err != nil {
		return nil, nil, nil, err
	}
	return scheduler, probers, newProber, nil
}

// selectScheduler builds the send scheduler the configured policy names, over the
// per-path health (and, for the weighted policy, quality) sources. active-backup is
// the P1 default; weighted is T21. The weighted knobs are validated at config load,
// so translating them here cannot fail on range — only NewWeighted's structural
// checks (which the wiring satisfies) apply.
func selectScheduler(cfg *config.Config, health []sched.PathHealth, quality []sched.PathQuality, clock telemetry.Clock, lg log.Logger) (sched.Scheduler, error) {
	switch cfg.Scheduler.Policy {
	case config.PolicyWeighted:
		sc := cfg.Scheduler
		return sched.NewWeighted(health, quality, sched.WeightedConfig{
			PerPathCapacity:   sc.PerPathCapacityFPS,
			EngageFraction:    sc.EngageFraction,
			DisengageFraction: sc.DisengageFraction,
			CollapseDwell:     sc.CollapseDwell,
			LoadTau:           sc.LoadTau,
			Pacing:            sc.PacingEnabled,
			PacingBurst:       sc.PacingBurstFrames,
			WeightRTTFloor:    sc.WeightRTTFloor,
			WeightLossFloor:   sc.WeightLossFloor,
		}, clock, lg)
	default:
		// active-backup (and the empty default, normalized to it at config load).
		return sched.NewActiveBackup(
			health,
			sched.Config{FailbackAfter: defaultFailbackDwell},
			clock,
			lg,
		)
	}
}

// Name is the created TUN interface name (for external addressing/routing).
func (t *Tunnel) Name() string { return t.name }

// Wait blocks until the device is torn down (its own Close, or an unrecoverable
// engine error).
func (t *Tunnel) Wait() { <-t.dev.Wait() }

// Close stops the probe loop, brings the device down, and releases the TUN and
// Bind. Idempotent. It also releases this tunnel's hold on the single-amnezia-
// engine-per-process guard exactly once, so a later Up may reconfigure the
// process-global amnezia state. Probing is stopped BEFORE the engine tears the
// bind's sockets down so no emission races the close.
func (t *Tunnel) Close() {
	// Shut the scrape endpoint FIRST so no in-flight /metrics scrape reads the Bind while
	// the engine tears its sockets down. reloadMu serializes this against a concurrent
	// SIGHUP-driven rebind.
	t.reloadMu.Lock()
	t.stopMetricsLocked()
	t.reloadMu.Unlock()
	if t.stopProbes != nil {
		t.stopProbes()
	}
	if t.stopReconcile != nil {
		t.stopReconcile()
	}
	if t.stopHubFailover != nil {
		t.stopHubFailover()
	}
	t.dev.Close()
	t.releaseOnce.Do(func() { globalAmneziaGuard.release(t.amnezia) })
}

// engineLogger adapts the amneziawg engine's logger onto wanbond's structured
// logger under a "wg" component. The engine is verbose only when the daemon runs
// at debug level; otherwise only its errors surface.
func engineLogger(lg log.Logger, level string) *awgdevice.Logger {
	wg := lg.Component("wg")
	verbosef := func(string, ...any) {}
	if strings.EqualFold(strings.TrimSpace(level), "debug") {
		verbosef = func(format string, args ...any) { wg.Debug(fmt.Sprintf(format, args...)) }
	}
	return &awgdevice.Logger{
		Verbosef: verbosef,
		Errorf:   func(format string, args ...any) { wg.Error(fmt.Sprintf(format, args...)) },
	}
}

// uapiConfig renders cfg into the newline-delimited UAPI set string the engine's
// IpcSet consumes. Keys are lowercase hex (UAPI's on-the-wire encoding), NOT the
// base64 form the TOML carries. Amnezia obfuscation keys are emitted only when the
// block is configured; an all-zero Amnezia block leaves the engine in plain
// WireGuard mode. The same amnezia parameters are applied on BOTH roles (edge and
// concentrator) as defense-in-depth — they must match end to end for the handshake
// to succeed (config validation makes each end specify a complete profile, D1).
func uapiConfig(cfg *config.Config) (string, error) {
	var b strings.Builder

	priv := cfg.WireGuard.PrivateKey.Bytes()
	fmt.Fprintf(&b, "private_key=%s\n", hex.EncodeToString(priv[:]))
	if cfg.Role == config.RoleConcentrator {
		fmt.Fprintf(&b, "listen_port=%d\n", cfg.WireGuard.ListenPort)
	}
	writeAmnezia(&b, cfg.Amnezia)

	for i, peer := range cfg.WireGuard.Peers {
		pub := peer.PublicKey.Bytes()
		fmt.Fprintf(&b, "public_key=%s\n", hex.EncodeToString(pub[:]))
		if len(peer.Endpoints) > 0 {
			// Endpoints[0] is the active/primary concentrator (Q18 ordered-endpoint
			// active-standby); it is populated from either the legacy single
			// `endpoint` field or the new ordered `endpoints` list (config.Peer.
			// resolveEndpoints), so both forms bring up the tunnel identically here.
			// Switching to a standby endpoint on hub loss is T57's job, not this
			// initial UAPI render.
			fmt.Fprintf(&b, "endpoint=%s\n", peer.Endpoints[0])
			// A keepalive keeps the edge->concentrator session warm and lets the
			// concentrator relearn the edge endpoint after a NAT rebind; only the
			// initiating (edge) side sets it.
			fmt.Fprintf(&b, "persistent_keepalive_interval=%d\n", keepaliveSeconds)
		}
		if len(peer.AllowedIPs) == 0 {
			return "", fmt.Errorf("peer %d (%s): at least one allowed_ip is required", i, hex.EncodeToString(pub[:8]))
		}
		for _, cidr := range peer.AllowedIPs {
			fmt.Fprintf(&b, "allowed_ip=%s\n", cidr)
		}
	}
	return b.String(), nil
}

// keepaliveSeconds is the edge's persistent-keepalive interval.
const keepaliveSeconds = 25

// writeAmnezia emits the nine amneziawg obfuscation UAPI keys, but only when the
// block is configured. When amnezia is unused, wanbond leaves the engine's
// PROCESS-GLOBAL message-type state untouched (see the amneziaGuard invariant).
// Config validation guarantees a configured block is complete and self-consistent
// (D1), and applyDefaults has already filled the standard magic headers (1..4)
// when they were omitted, so the emitted set never carries an h*=0 sentinel.
func writeAmnezia(b *strings.Builder, a config.Amnezia) {
	if !a.Configured() {
		return
	}
	fmt.Fprintf(b, "jc=%d\njmin=%d\njmax=%d\ns1=%d\ns2=%d\nh1=%d\nh2=%d\nh3=%d\nh4=%d\n",
		a.Jc, a.Jmin, a.Jmax, a.S1, a.S2, a.H1, a.H2, a.H3, a.H4)
}
